def _patch_codex_tool_timeout() -> None:
    global _CODEX_PATCH_APPLIED
    if _CODEX_PATCH_APPLIED:
        return
    from caw.providers.codex import CodexSession

    _orig = CodexSession._mcp_config_args

    def _patched(self) -> list[str]:
