            for func in functions:
                func_id = func.id if func.id else f"{file_path}:{func.name}"
                self.functions[func_id] = func

            self.call_relationships.extend(relationships)
        except Exception as e:
            logger.error(f"Failed to analyze PHP file {file_path}: {e}", exc_info=True)

    def _resolve_call_relationships(self):
        """
        Resolve function call relationships across all languages.

        Attempts to match function calls to actual function definitions,
        handling cross-language calls where possible.
        """
        func_lookup = {}
        for func_id, func_info in self.functions.items():
            func_lookup[func_id] = func_id
            func_lookup[func_info.name] = func_id
            if func_info.component_id:
                func_lookup[func_info.component_id] = func_id
                # Extract short name: handle both new (path::Name) and legacy (path.Name) formats
                if "::" in func_info.component_id:
                    method_name = func_info.component_id.split("::")[-1]
                else:
                    method_name = func_info.component_id.split(".")[-1]
                if method_name not in func_lookup:
                    func_lookup[method_name] = func_id

        resolved_count = 0
        for relationship in self.call_relationships:
            callee_name = relationship.callee

            if callee_name in func_lookup:
                relationship.callee = func_lookup[callee_name]
                relationship.is_resolved = True
                resolved_count += 1
            elif "::" in callee_name or "." in callee_name:
                if callee_name in func_lookup:
                    relationship.callee = func_lookup[callee_name]
                    relationship.is_resolved = True
                    resolved_count += 1
                else:
                    if "::" in callee_name:
                        method_name = callee_name.split("::")[-1]
                    else:
                        method_name = callee_name.split(".")[-1]
                    if method_name in func_lookup:
                        relationship.callee = func_lookup[method_name]
                        relationship.is_resolved = True
                        resolved_count += 1

    def _deduplicate_relationships(self):
        """
        Deduplicate call relationships based on caller-callee pairs.

        Removes duplicate relationships while preserving the first occurrence.
        This helps eliminate noise from multiple calls to the same function.
        """
        seen = set()
        unique_relationships = []

        for rel in self.call_relationships:
            key = (rel.caller, rel.callee)
            if key not in seen:
                seen.add(key)
                unique_relationships.append(rel)

        self.call_relationships = unique_relationships

    def _generate_visualization_data(self) -> Dict:
        """
        Generate visualization data for graph rendering.

        Creates Cytoscape.js compatible graph data with nodes and edges.

        Returns:
            Dict: Visualization data with cytoscape elements and summary
        """
        cytoscape_elements = []

        for func_id, func_info in self.functions.items():
            node_classes = []
            if func_info.node_type == "method":
                node_classes.append("node-method")
            else:
                node_classes.append("node-function")

            file_ext = Path(func_info.file_path).suffix.lower()
            if file_ext == ".py":
                node_classes.append("lang-python")
            elif file_ext == ".js":
                node_classes.append("lang-javascript")
            elif file_ext == ".ts":
                node_classes.append("lang-typescript")
            elif file_ext in [".c", ".h"]:
                node_classes.append("lang-c")
            elif file_ext in [".cpp", ".cc", ".cxx", ".hpp", ".hxx"]:
                node_classes.append("lang-cpp")
            elif file_ext in [".kt", ".kts"]:
                node_classes.append("lang-kotlin")
            elif file_ext in [".php", ".phtml", ".inc"]:
                node_classes.append("lang-php")

            cytoscape_elements.append(
                {
                    "data": {
                        "id": func_id,
                        "label": func_info.name,
                        "file": func_info.file_path,
                        "type": func_info.node_type or "function",
                        "language": CODE_EXTENSIONS.get(file_ext, "unknown"),
                    },
                    "classes": " ".join(node_classes),
                }
            )

        resolved_rels = [r for r in self.call_relationships if r.is_resolved]
        for rel in resolved_rels:
            cytoscape_elements.append(
                {
                    "data": {
                        "id": f"{rel.caller}->{rel.callee}",
                        "source": rel.caller,
                        "target": rel.callee,
                        "line": rel.call_line,
                    },
                    "classes": "edge-call",
                }
            )

        summary = {
            "total_nodes": len(self.functions),
            "total_edges": len(resolved_rels),
            "unresolved_calls": len(self.call_relationships) - len(resolved_rels),
        }

        return {
            "cytoscape": {"elements": cytoscape_elements},
            "summary": summary,
        }

    def generate_llm_format(self) -> Dict:
        """Generate clean format optimized for LLM consumption."""
        return {
            "functions": [
                {
                    "name": func.name,
                    "file": Path(func.file_path).name,
                    "purpose": (func.docstring.split("\n")[0] if func.docstring else None),
                    "parameters": func.parameters,
                    "is_recursive": func.name
                    in [
                        rel.callee
                        for rel in self.call_relationships
                        if rel.caller.endswith(func.name)
                    ],
                }
                for func in self.functions.values()
            ],
            "relationships": {
                func.name: {
                    "calls": [
                        rel.callee.split(":")[-1]
                        for rel in self.call_relationships
                        if rel.caller.endswith(func.name) and rel.is_resolved
                    ],
                    "called_by": [
                        rel.caller.split(":")[-1]
                        for rel in self.call_relationships
                        if rel.callee.endswith(func.name) and rel.is_resolved
                    ],
                }
                for func in self.functions.values()
            },
        }

    def _select_most_connected_nodes(self, target_count: int):
        """
        Select the most connected nodes from the call graph.

        Args:
            target_count: The number of nodes to select
        """
        if len(self.functions) <= target_count:
            return

        if not self.call_relationships:
            logger.warning("No call relationships found - keeping all functions by name")
            func_ids = list(self.functions.keys())[:target_count]
            self.functions = {fid: func for fid, func in self.functions.items() if fid in func_ids}
            return

        graph = {}
        for rel in self.call_relationships:
            if rel.caller in self.functions:
                if rel.caller not in graph:
                    graph[rel.caller] = set()
            if rel.callee in self.functions:
                if rel.callee not in graph:
                    graph[rel.callee] = set()

            if rel.caller in graph and rel.callee in graph:
                graph[rel.caller].add(rel.callee)
                graph[rel.callee].add(rel.caller)

        degree_centrality = {}
        for func_id in self.functions.keys():
            degree_centrality[func_id] = len(graph.get(func_id, set()))

        sorted_func_ids = sorted(degree_centrality, key=degree_centrality.get, reverse=True)

        selected_func_ids = sorted_func_ids[:target_count]

        original_func_count = len(self.functions)
        self.functions = {
            fid: func for fid, func in self.functions.items() if fid in selected_func_ids
        }

        original_rel_count = len(self.call_relationships)
        self.call_relationships = [
            rel
            for rel in self.call_relationships
            if rel.caller in selected_func_ids and rel.callee in selected_func_ids
        ]

def sanitize_github_url(github_url: str) -> str:
    """
    Sanitize GitHub URL to ensure proper format and remove extra path components.

    Args:
        github_url: Raw GitHub URL or repository path

    Returns:
        str: Sanitized GitHub URL suitable for cloning
    """

    url = github_url.strip()

    protocol = "https://"
    if url.startswith("https://"):
        url = url[8:]
    elif url.startswith("http://"):
        url = url[7:]
        protocol = "http://"

    if url.startswith("www."):
        url = url[4:]

    parts = url.split("/")

    if url.startswith("github.com/"):
        url_parts = url.split("/")
        if len(url_parts) >= 3:
            owner = url_parts[1]
            repo = url_parts[2]
        else:
            return github_url
    elif "/" in url and not url.startswith("github.com"):
        url_parts = url.split("/")
        if len(url_parts) >= 2:
            owner = url_parts[0]
            repo = url_parts[1]
        else:
            return github_url
    else:
        return github_url

    if repo.endswith(".git"):
        repo = repo[:-4]

    return f"{protocol}github.com/{owner}/{repo}"

def cleanup_repository_safe(repo_dir: str) -> bool:
    """
    Windows-safe removal of the cloned repository directory.
    Handles read-only files and permission issues common on Windows.

    Args:
        repo_dir: Path to the repository directory to remove

    Returns:
        bool: True if cleanup successful, False otherwise
    """

    def handle_remove_readonly(func, path, exc):
        """Error handler for Windows read-only files."""
        if os.path.exists(path):
            os.chmod(path, stat.S_IWRITE)
            func(path)

    try:
        if os.path.exists(repo_dir):
            if os.name == "nt":
                shutil.rmtree(repo_dir, onerror=handle_remove_readonly)
            else:
                shutil.rmtree(repo_dir)
            return True
        return False
    except PermissionError as e:
        try:
            time.sleep(1)
            if os.path.exists(repo_dir):
                for root, dirs, files in os.walk(repo_dir):
                    for dir in dirs:
                        os.chmod(os.path.join(root, dir), stat.S_IWRITE)
                    for file in files:
                        file_path = os.path.join(root, file)
                        if os.path.exists(file_path):
                            os.chmod(file_path, stat.S_IWRITE)
                shutil.rmtree(repo_dir)
            return True
        except Exception as retry_e:
            print(f"⚠️ Warning: Failed to cleanup {repo_dir} after retry: {str(retry_e)}")
            return False
    except Exception as e:
        print(f"⚠️ Warning: Failed to cleanup {repo_dir}: {str(e)}")
        return False

def handle_remove_readonly(func, path, exc):
    """Error handler for Windows read-only files."""
    if os.path.exists(path):
        os.chmod(path, stat.S_IWRITE)
        func(path)

class RepoAnalyzer:
    def __init__(
        self,
        include_patterns: Optional[List[str]] = None,
        exclude_patterns: Optional[List[str]] = None,
    ) -> None:
        # Include patterns: if specified, use ONLY those patterns (replaces defaults)
        self.include_patterns = (
            include_patterns if include_patterns is not None else DEFAULT_INCLUDE_PATTERNS
        )
        # Exclude patterns: if specified, MERGE with default ignore patterns
        self.exclude_patterns = (
            list(DEFAULT_IGNORE_PATTERNS) + exclude_patterns
            if exclude_patterns is not None
            else list(DEFAULT_IGNORE_PATTERNS)
        )

    def analyze_repository_structure(self, repo_dir: str) -> Dict:
        file_tree = self._build_file_tree(repo_dir)
        return {
            "file_tree": file_tree,
            "summary": {
                "total_files": self._count_files(file_tree),
                "total_size_kb": self._calculate_size(file_tree),
            },
        }

    def _build_file_tree(self, repo_dir: str) -> Dict:
        def build_tree(path: Path, base_path: Path) -> Optional[Dict]:
            relative_path = path.relative_to(base_path)
            relative_path_str = str(relative_path)

            # 🚫 Reject symlinks
            if path.is_symlink():
                return None

            # 🚫 Reject escaped paths (e.g., symlinks pointing outside)
            try:
                if not path.resolve().is_relative_to(base_path.resolve()):
                    return None
            except AttributeError:
                if not str(path.resolve()).startswith(str(base_path.resolve())):
                    return None

            if self._should_exclude_path(relative_path_str, path.name):
                return None

            if path.is_file():
                if not self._should_include_file(relative_path_str, path.name):
                    return None

                size = path.stat().st_size
                return {
                    "type": "file",
                    "name": path.name,
                    "path": relative_path_str,
                    "extension": path.suffix,
                    "_size_bytes": size,
                }

            elif path.is_dir():
                children = []
                try:
                    for child in sorted(path.iterdir()):
                        child_tree = build_tree(child, base_path)
                        if child_tree is not None:
                            children.append(child_tree)
                except PermissionError:
                    pass

                if children or str(relative_path) == ".":
                    return {
                        "type": "directory",
                        "name": path.name,
                        "path": relative_path_str,
                        "children": children,
                    }
                return None

            # Other types (sockets, devices, etc.)
            return None

        return build_tree(Path(repo_dir), Path(repo_dir))

    def _should_exclude_path(self, path: str, filename: str) -> bool:
        for pattern in self.exclude_patterns:
            if fnmatch.fnmatch(path, pattern) or fnmatch.fnmatch(filename, pattern):
                return True
            if pattern.endswith("/") and path.startswith(pattern.rstrip("/")):
                return True
            if path.startswith(pattern + "/") or path == pattern:
                return True
            if pattern in path.split("/"):
                return True
        return False

    def _should_include_file(self, path: str, filename: str) -> bool:
        if not self.include_patterns:
            return True
        for pattern in self.include_patterns:
            if fnmatch.fnmatch(path, pattern) or fnmatch.fnmatch(filename, pattern):
                return True
        return False

    def _count_files(self, tree: Dict) -> int:
        if tree["type"] == "file":
            return 1
        return sum(self._count_files(child) for child in tree.get("children", []))

    def _calculate_size(self, tree: Dict) -> float:
        if tree["type"] == "file":
            return tree.get("_size_bytes", 0) / 1024
        return sum(self._calculate_size(child) for child in tree.get("children", []))

class TreeSitterCAnalyzer:
	def __init__(self, file_path: str, content: str, repo_path: str = None):
		self.file_path = Path(file_path)
		self.content = content
		self.repo_path = repo_path or ""
		self.nodes: List[Node] = []
		self.call_relationships: List[CallRelationship] = []
		self._analyze()

	def _get_module_path(self) -> str:
		if self.repo_path:
			try:
				rel_path = os.path.relpath(str(self.file_path), self.repo_path)
			except ValueError:
				rel_path = str(self.file_path)
		else:
			rel_path = str(self.file_path)

		for ext in ['.c', '.h']:
			if rel_path.endswith(ext):
				rel_path = rel_path[:-len(ext)]
				break
		return rel_path.replace('/', '.').replace('\\', '.')

	def _get_relative_path(self) -> str:
		if self.repo_path:
			try:
				return os.path.relpath(str(self.file_path), self.repo_path)
			except ValueError:
				return str(self.file_path)
		else:
			return str(self.file_path)

	def _get_component_id(self, name: str) -> str:
		rel_path = self._get_relative_path()
		return f"{rel_path}::{name}"

	def _analyze(self):
		language_capsule = tree_sitter_c.language()
		c_language = Language(language_capsule)
		parser = Parser(c_language)
		tree = parser.parse(bytes(self.content, "utf8"))
		root = tree.root_node
		lines = self.content.splitlines()

		top_level_nodes = {}

		# collect all top-level nodes using recursive traversal
		self._extract_nodes(root, top_level_nodes, lines)

		# extract relationships between top-level nodes
		self._extract_relationships(root, top_level_nodes)

	def _extract_nodes(self, node, top_level_nodes, lines):
		"""Recursively extract top-level nodes (functions, structs, and global variables)."""
		node_type = None
		node_name = None

		if node.type == "function_definition":
			node_type = "function"
			# look for function_declarator
			declarator = next((c for c in node.children if c.type == "function_declarator"), None)
			if declarator:
				identifier = next((c for c in declarator.children if c.type == "identifier"), None)
				if identifier:
					node_name = identifier.text.decode()
		elif node.type == "struct_specifier":
			# Extract struct definitions: struct Name { ... }
			node_type = "struct"
			# Find type_identifier that represents the struct name
			for child in node.children:
				if child.type == "type_identifier":
					node_name = child.text.decode()
					break
		elif node.type == "type_definition":
			# Handle typedef struct definitions: typedef struct { ... } Name;
			# Check if this typedef contains a struct
			struct_spec = next((c for c in node.children if c.type == "struct_specifier"), None)
			if struct_spec:
				node_type = "struct"
				# The typedef name is the type_identifier at the end
				type_declarator = next((c for c in node.children if c.type == "type_identifier"), None)
				if type_declarator:
					node_name = type_declarator.text.decode()
		elif node.type == "declaration":
			if self._is_global_variable(node):
				node_type = "variable"
				for child in node.children:
					if child.type == "init_declarator":
						identifier = next((c for c in child.children if c.type == "identifier"), None)
						if identifier:
							node_name = identifier.text.decode()
							break
						pointer_declarator = next((c for c in child.children if c.type == "pointer_declarator"), None)
						if pointer_declarator:
							identifier = next((c for c in pointer_declarator.children if c.type == "identifier"), None)
							if identifier:
								node_name = identifier.text.decode()
								break
					elif child.type == "identifier":
						node_name = child.text.decode()
						break

		if node_type and node_name:
			component_id = self._get_component_id(node_name)
			relative_path = self._get_relative_path()
			node_obj = Node(
				id=component_id,
				name=node_name,
				component_type=node_type,
				file_path=str(self.file_path),
				relative_path=relative_path,
				source_code="\n".join(lines[node.start_point[0]:node.end_point[0]+1]),
				start_line=node.start_point[0]+1,
				end_line=node.end_point[0]+1,
				has_docstring=False,
				docstring="",
				parameters=None,
				node_type=node_type,
				base_classes=None,
				class_name=None,
				display_name=f"{node_type} {node_name}",
				component_id=component_id
			)

			if node_type in ["function", "struct"]:
				self.nodes.append(node_obj)
			top_level_nodes[node_name] = node_obj

		for child in node.children:
			self._extract_nodes(child, top_level_nodes, lines)

	def _is_global_variable(self, node) -> bool:
		parent = node.parent
		while parent:
			if parent.type == "function_definition":
				return False
			parent = parent.parent
		return True

	def _extract_relationships(self, node, top_level_nodes):
		"""Extract various types of relationships between top-level nodes."""

		# 1. function calls other functions
		if node.type == "call_expression":
			containing_function = self._find_containing_function(node, top_level_nodes)
			if containing_function:
				containing_function_id = self._get_component_id(containing_function)

				# Get called function name
				function_node = next((c for c in node.children if c.type == "identifier"), None)
				if function_node:
					called_function = function_node.text.decode()
					if not self._is_system_function(called_function):
						self.call_relationships.append(CallRelationship(
							caller=containing_function_id,
							callee=called_function,  # Use simple name for cross-file resolution
							call_line=node.start_point[0]+1,
							is_resolved=False  # Let CallGraphAnalyzer resolve
						))

		# 2. function uses global variables
		if node.type == "identifier":
			containing_function = self._find_containing_function(node, top_level_nodes)
			if containing_function:
				var_name = node.text.decode()
				# Check if this identifier refers to a global variable
				if var_name in top_level_nodes and top_level_nodes[var_name].component_type == "variable":
					containing_function_id = self._get_component_id(containing_function)
					var_component_id = self._get_component_id(var_name)
					self.call_relationships.append(CallRelationship(
						caller=containing_function_id,
						callee=var_component_id,
						call_line=node.start_point[0]+1,
						is_resolved=True  # Local file relationship
					))

		# Recursively process children
		for child in node.children:
			self._extract_relationships(child, top_level_nodes)

	def _find_containing_function(self, node, top_level_nodes):
		"""Find the function that contains this node."""
		current = node.parent
		while current:
			if current.type == "function_definition":
				# Get function name
				declarator = next((c for c in current.children if c.type == "function_declarator"), None)
				if declarator:
					identifier = next((c for c in declarator.children if c.type == "identifier"), None)
					if identifier:
						func_name = identifier.text.decode()
						if func_name in top_level_nodes:
							return func_name
			current = current.parent
		return None

	def _is_system_function(self, func_name: str) -> bool:
		"""Check if function is a system/library function."""
		# Common C library functions
		system_functions = {
			"printf", "scanf", "malloc", "free", "strlen", "strcpy", "strcmp", 
			"memcpy", "memset", "exit", "abort", "fopen", "fclose", "fread", "fwrite",
			"SDL_Init", "SDL_CreateWindow", "SDL_Log", "SDL_GetError", "SDL_Quit"
		}
		return func_name in system_functions

def analyze_c_file(file_path: str, content: str, repo_path: str = None) -> Tuple[List[Node], List[CallRelationship]]:
	analyzer = TreeSitterCAnalyzer(file_path, content, repo_path)
	return analyzer.nodes, analyzer.call_relationships

class TreeSitterCppAnalyzer:
	def __init__(self, file_path: str, content: str, repo_path: str = None):
		self.file_path = Path(file_path)
		self.content = content
		self.repo_path = repo_path or ""
		self.nodes: List[Node] = []
		self.call_relationships: List[CallRelationship] = []
		self._analyze()

	def _get_module_path(self) -> str:
		if self.repo_path:
			try:
				rel_path = os.path.relpath(str(self.file_path), self.repo_path)
			except ValueError:
				rel_path = str(self.file_path)
		else:
			rel_path = str(self.file_path)

		for ext in ['.cpp', '.cc', '.cxx', '.hpp', '.h']:
			if rel_path.endswith(ext):
				rel_path = rel_path[:-len(ext)]
				break
		return rel_path.replace('/', '.').replace('\\', '.')

	def _get_relative_path(self) -> str:
		if self.repo_path:
			try:
				return os.path.relpath(str(self.file_path), self.repo_path)
			except ValueError:
				return str(self.file_path)
		else:
			return str(self.file_path)

	def _get_component_id(self, name: str, parent_class: str = None) -> str:
		rel_path = self._get_relative_path()
		if parent_class:
			return f"{rel_path}::{parent_class}.{name}"
		return f"{rel_path}::{name}"

	def _analyze(self):
		language_capsule = tree_sitter_cpp.language()
		cpp_language = Language(language_capsule)
		parser = Parser(cpp_language)
		tree = parser.parse(bytes(self.content, "utf8"))
		root = tree.root_node
		lines = self.content.splitlines()

		top_level_nodes = {}

		# collect all top-level nodes using recursive traversal
		self._extract_nodes(root, top_level_nodes, lines)

		# extract relationships between top-level nodes
		self._extract_relationships(root, top_level_nodes)

	def _extract_nodes(self, node, top_level_nodes, lines):
		"""Recursively extract top-level nodes (classes, functions, global variables)."""
		node_type = None
		node_name = None

		if node.type == "class_specifier":
			# "class" + type_identifier + { ... }
			node_type = "class"
			# Find type_identifier that represents the class name
			for child in node.children:
				if child.type == "type_identifier":
					node_name = child.text.decode()
					break
		elif node.type == "struct_specifier":
			# "struct" + type_identifier + { ... }
			node_type = "struct"
			# Find type_identifier that represents the struct name
			for child in node.children:
				if child.type == "type_identifier":
					node_name = child.text.decode()
					break
		elif node.type == "function_definition":
			# Check if this is inside a class or function
			containing_class = self._find_containing_class_for_method(node)
			if containing_class:
				node_type = "method"
			else:
				node_type = "function"

			declarator = next((c for c in node.children if c.type == "function_declarator"), None)
			if declarator:
				for child in declarator.children:
					if child.type == "identifier":
						node_name = child.text.decode()
						break
					elif child.type == "field_identifier":
						node_name = child.text.decode()
						break
					elif child.type == "qualified_identifier":
						identifiers = [c for c in child.children if c.type == "identifier"]
						if identifiers:
							node_name = identifiers[-1].text.decode()
							break
		elif node.type == "declaration":
			if self._is_global_variable(node):
				node_type = "variable"
				for child in node.children:
					if child.type == "init_declarator":
						identifier = next((c for c in child.children if c.type == "identifier"), None)
						if identifier:
							node_name = identifier.text.decode()
							break
					elif child.type == "identifier":
						node_name = child.text.decode()
						break
		elif node.type == "namespace_definition":
			node_type = "namespace"
			found_namespace_keyword = False
			for child in node.children:
				if child.type == "namespace":
					found_namespace_keyword = True
				elif found_namespace_keyword and child.type == "identifier":
					node_name = child.text.decode()
					break

		if node_type and node_name:
			if node_type == "method":
				component_id = self._get_component_id(node_name, containing_class)
				top_level_key = component_id
			else:
				component_id = self._get_component_id(node_name)
				top_level_key = node_name

			relative_path = self._get_relative_path()

			node_obj = Node(
				id=component_id,
				name=node_name,
				component_type=node_type,
				file_path=str(self.file_path),
				relative_path=relative_path,
				source_code="\n".join(lines[node.start_point[0]:node.end_point[0]+1]),
				start_line=node.start_point[0]+1,
				end_line=node.end_point[0]+1,
				has_docstring=False,
				docstring="",
				parameters=None,
				node_type=node_type,
				base_classes=None,
				class_name=containing_class if node_type == "method" else None,
				display_name=f"{node_type} {node_name}",
				component_id=component_id
			)

			top_level_nodes[top_level_key] = node_obj

			if node_type in ["class", "struct", "function"]:
				self.nodes.append(node_obj)

		# Recursively process children
		for child in node.children:
			self._extract_nodes(child, top_level_nodes, lines)

	def _is_global_variable(self, node) -> bool:
		"""Check if a declaration node is a global variable."""
		parent = node.parent
		while parent:
			if parent.type in ["function_definition", "class_specifier", "struct_specifier"]:
				return False
			parent = parent.parent
		return True

	def _find_containing_class_for_method(self, node):
		"""Find the class that contains this method definition."""
		current = node.parent
		while current:
			if current.type == "class_specifier":
				# Get class name
				for child in current.children:
					if child.type == "type_identifier":
						return child.text.decode()
			elif current.type == "struct_specifier":
				# Get struct name 
				for child in current.children:
					if child.type == "type_identifier":
						return child.text.decode()
			current = current.parent
		return None

	def _extract_relationships(self, node, top_level_nodes):
		if node.type == "call_expression":
			containing_function = self._find_containing_function_or_method(node, top_level_nodes)
			if containing_function:
				containing_function_id = self._get_component_id_for_function(containing_function, top_level_nodes)

				# Get called function name 
				called_function = None
				for child in node.children:
					if child.type == "identifier":
						called_function = child.text.decode()
						break
					elif child.type == "field_expression":
						method_name = None
						for field_child in child.children:
							if field_child.type == "field_identifier":
								method_name = field_child.text.decode()
								break
						if method_name:
							called_function = method_name
							break

				if called_function and not self._is_system_function(called_function):
					target_class = self._find_class_containing_method(called_function, top_level_nodes)

					if target_class:
						target_class_id = self._get_component_id(target_class)
						self.call_relationships.append(CallRelationship(
							caller=containing_function_id,
							callee=target_class_id,
							call_line=node.start_point[0]+1,
							relationship_type="calls"
						))
					elif called_function in top_level_nodes:
						called_function_id = self._get_component_id(called_function)
						self.call_relationships.append(CallRelationship(
							caller=containing_function_id,
							callee=called_function_id,
							call_line=node.start_point[0]+1,
							relationship_type="calls"
						))

		elif node.type == "base_class_clause":
			# Find the containing class
			containing_class = self._find_containing_class(node)
			if containing_class:
				# Extract base class names
				for child in node.children:
					if child.type == "type_identifier":
						base_class = child.text.decode()
						containing_class_id = self._get_component_id(containing_class)
						self.call_relationships.append(CallRelationship(
							caller=containing_class_id,
							callee=base_class,
							call_line=node.start_point[0]+1,
							relationship_type="inherits"
						))

		elif node.type == "new_expression":
			containing_function = self._find_containing_function_or_method(node, top_level_nodes)
			if containing_function:
				containing_function_id = self._get_component_id_for_function(containing_function, top_level_nodes)

				# Get the class being instantiated
				for child in node.children:
					if child.type == "type_identifier":
						class_name = child.text.decode()
						if class_name in top_level_nodes:
							class_id = self._get_component_id(class_name)
							self.call_relationships.append(CallRelationship(
								caller=containing_function_id,
								callee=class_id,
								call_line=node.start_point[0]+1,
								relationship_type="creates"
							))
						break

		elif node.type == "identifier":
			parent = node.parent
			if parent and parent.type not in ["function_definition", "class_specifier", "declaration", "function_declarator"]:
				var_name = node.text.decode()
				if var_name in top_level_nodes and top_level_nodes[var_name].component_type == "variable":
					containing_function = self._find_containing_function_or_method(node, top_level_nodes)
					if containing_function and containing_function != var_name:
						containing_function_id = self._get_component_id_for_function(containing_function, top_level_nodes)
						self.call_relationships.append(CallRelationship(
							caller=containing_function_id,
							callee=var_name,
							call_line=node.start_point[0]+1,
							relationship_type="uses"
						))

		# Recursively process children
		for child in node.children:
			self._extract_relationships(child, top_level_nodes)

	def _find_containing_function(self, node, top_level_nodes):
		"""Find the function that contains this node."""
		current = node.parent
		while current:
			if current.type == "function_definition":
				# Get function name
				declarator = next((c for c in current.children if c.type == "function_declarator"), None)
				if declarator:
					identifier = next((c for c in declarator.children if c.type == "identifier"), None)
					if identifier:
						func_name = identifier.text.decode()
						if func_name in top_level_nodes:
							return func_name
			current = current.parent
		return None

	def _find_containing_function_or_method(self, node, top_level_nodes):
		"""Find the function or method that contains this node."""
		current = node.parent
		while current:
			if current.type == "function_definition":
				declarator = next((c for c in current.children if c.type == "function_declarator"), None)
				if declarator:
					identifier = next((c for c in declarator.children if c.type == "identifier"), None)
					if identifier:
						func_name = identifier.text.decode()
						return func_name
			current = current.parent
		return None

	def _get_component_id_for_function(self, func_name, top_level_nodes):
		if func_name in top_level_nodes:
			node_obj = top_level_nodes[func_name]
			if hasattr(node_obj, 'class_name') and node_obj.class_name:
				return self._get_component_id(func_name, node_obj.class_name)
			else:
				return self._get_component_id(func_name)
		return self._get_component_id(func_name)

	def _find_containing_class(self, node):
		"""Find the class that contains this node."""
		current = node.parent
		while current:
			if current.type == "class_specifier":
				# Get class name
				for child in current.children:
					if child.type == "type_identifier":
						return child.text.decode()
			current = current.parent
		return None

	def _is_system_function(self, func_name: str) -> bool:
		"""Check if function is a system/library function."""
		system_functions = {
			'printf', 'scanf', 'malloc', 'free', 'strlen', 'strcpy', 'strcmp',
			'cout', 'cin', 'endl', 'std', 'new', 'delete'
		}
		return func_name in system_functions

	def _find_class_containing_method(self, method_name, top_level_nodes):
		for node_name, node_obj in top_level_nodes.items():
			if node_obj.component_type in ["class", "struct"]:
				if self._class_has_method(node_obj, method_name):
					return node_name
		return None

	def _class_has_method(self, class_node, method_name):
		lines = class_node.source_code.split('\n')
		for line in lines:
			if f'{method_name}(' in line and ('void' in line or 'int' in line or 'bool' in line or class_node.name in line):
				return True
		return False

def analyze_cpp_file(file_path: str, content: str, repo_path: str = None) -> Tuple[List[Node], List[CallRelationship]]:
	analyzer = TreeSitterCppAnalyzer(file_path, content, repo_path)
	return analyzer.nodes, analyzer.call_relationships

class TreeSitterCSharpAnalyzer:
	def __init__(self, file_path: str, content: str, repo_path: str = None):
		self.file_path = Path(file_path)
		self.content = content
		self.repo_path = repo_path or ""
		self.nodes: List[Node] = []
		self.call_relationships: List[CallRelationship] = []
		self._analyze()

	def _get_module_path(self) -> str:
		if self.repo_path:
			try:
				rel_path = os.path.relpath(str(self.file_path), self.repo_path)
			except ValueError:
				rel_path = str(self.file_path)
		else:
			rel_path = str(self.file_path)

		for ext in ['.cs']:
			if rel_path.endswith(ext):
				rel_path = rel_path[:-len(ext)]
				break
		return rel_path.replace('/', '.').replace('\\', '.')

	def _get_relative_path(self) -> str:
		if self.repo_path:
			try:
				return os.path.relpath(str(self.file_path), self.repo_path)
			except ValueError:
				return str(self.file_path)
		else:
			return str(self.file_path)

	def _get_component_id(self, name: str) -> str:
		rel_path = self._get_relative_path()
		return f"{rel_path}::{name}"

	def _analyze(self):
		language_capsule = tree_sitter_c_sharp.language()
		cs_language = Language(language_capsule)
		parser = Parser(cs_language)
		tree = parser.parse(bytes(self.content, "utf8"))
		root = tree.root_node
		lines = self.content.splitlines()

		top_level_nodes = {}

		self._extract_nodes(root, top_level_nodes, lines)

		self._extract_relationships(root, top_level_nodes)

	def _extract_nodes(self, node, top_level_nodes, lines):
		node_type = None
		node_name = None

		if node.type == "class_declaration":
			# modifiers + class + identifier + body
			is_abstract = any(c.type == "modifier" and "abstract" in c.text.decode() for c in node.children)
			is_static = any(c.type == "modifier" and "static" in c.text.decode() for c in node.children)
			if is_static:
				node_type = "static class"
			elif is_abstract:
				node_type = "abstract class"
			else:
				node_type = "class"
			# find identifier that comes after class keyword
			found_class_keyword = False
			for child in node.children:
				if child.type == "class":
					found_class_keyword = True
				elif found_class_keyword and child.type == "identifier":
					node_name = child.text.decode()
					break
		elif node.type == "interface_declaration":
			node_type = "interface"
			# find identifier that comes after interface keyword
			found_interface_keyword = False
			for child in node.children:
				if child.type == "interface":
					found_interface_keyword = True
				elif found_interface_keyword and child.type == "identifier":
					node_name = child.text.decode()
					break
		elif node.type == "struct_declaration":
			node_type = "struct"
			# find identifier that comes after struct keyword
			found_struct_keyword = False
			for child in node.children:
				if child.type == "struct":
					found_struct_keyword = True
				elif found_struct_keyword and child.type == "identifier":
					node_name = child.text.decode()
					break
		elif node.type == "enum_declaration":
			node_type = "enum"
			# find identifier that comes after enum keyword
			found_enum_keyword = False
			for child in node.children:
				if child.type == "enum":
					found_enum_keyword = True
				elif found_enum_keyword and child.type == "identifier":
					node_name = child.text.decode()
					break
		elif node.type == "record_declaration":
			node_type = "record"
			# find identifier that comes after record keyword
			found_record_keyword = False
			for child in node.children:
				if child.type == "record":
					found_record_keyword = True
				elif found_record_keyword and child.type == "identifier":
					node_name = child.text.decode()
					break
		elif node.type == "delegate_declaration":
			node_type = "delegate"
			for child in node.children:
				if child.type == "identifier":
					node_name = child.text.decode()
					break

		if node_type and node_name:
			component_id = self._get_component_id(node_name)
			relative_path = self._get_relative_path()
			node_obj = Node(
				id=component_id,
				name=node_name,
				component_type=node_type,
				file_path=str(self.file_path),
				relative_path=relative_path,
				source_code="\n".join(lines[node.start_point[0]:node.end_point[0]+1]),
				start_line=node.start_point[0]+1,
				end_line=node.end_point[0]+1,
				has_docstring=False,
				docstring="",
				parameters=None,
				node_type=node_type,
				base_classes=None,
				class_name=None,
				display_name=f"{node_type} {node_name}",
				component_id=component_id
			)
			self.nodes.append(node_obj)
			top_level_nodes[node_name] = node_obj

		for child in node.children:
			self._extract_nodes(child, top_level_nodes, lines)

	def _extract_relationships(self, node, top_level_nodes):
		containing_class = self._find_containing_class(node, top_level_nodes)

		if node.type == "class_declaration":
			class_name = self._get_identifier_name_cs(node)
			if class_name:
				class_component_id = self._get_component_id(class_name)

				base_list = next((c for c in node.children if c.type == "base_list"), None)
				if base_list:
					for child in base_list.children:
						if child.type == "identifier":
							base_name = child.text.decode()
							if base_name in [n.name for n in top_level_nodes.values()]:
								base_component_id = self._get_component_id(base_name)
								self.call_relationships.append(CallRelationship(
									caller=class_component_id,
									callee=base_component_id,
									call_line=node.start_point[0]+1,
									is_resolved=True
								))

		elif node.type == "property_declaration":
			if containing_class:
				containing_class_id = self._get_component_id(containing_class)
				type_identifiers = [c for c in node.children if c.type == "identifier"]
				if len(type_identifiers) >= 2:
					property_type = type_identifiers[0].text.decode()
					if property_type and not self._is_primitive_type(property_type):
						self.call_relationships.append(CallRelationship(
							caller=containing_class_id,
							callee=property_type,  
							call_line=node.start_point[0]+1,
							is_resolved=False  
						))

		elif node.type == "field_declaration":
			if containing_class:
				containing_class_id = self._get_component_id(containing_class)
				type_node = next((c for c in node.children if c.type == "identifier"), None)
				if type_node:
					field_type = type_node.text.decode()
					if field_type and not self._is_primitive_type(field_type):
						self.call_relationships.append(CallRelationship(
							caller=containing_class_id,
							callee=field_type, 
							call_line=node.start_point[0]+1,
							is_resolved=False  
						))

		elif node.type == "method_declaration":
			if containing_class:
				containing_class_id = self._get_component_id(containing_class)
				param_list = next((c for c in node.children if c.type == "parameter_list"), None)
				if param_list:
					for child in param_list.children:
						if child.type == "parameter":
							type_node = next((c for c in child.children if c.type == "identifier"), None)
							if type_node:
								param_type = type_node.text.decode()
								if param_type and not self._is_primitive_type(param_type):
									self.call_relationships.append(CallRelationship(
										caller=containing_class_id,
										callee=param_type,  
										call_line=node.start_point[0]+1,
										is_resolved=False  
									))

		# Recursively process children
		for child in node.children:
			self._extract_relationships(child, top_level_nodes)

	def _is_primitive_type(self, type_name: str) -> bool:
		"""Check if type is a C# primitive or common built-in type."""
		primitives = {
			"bool", "byte", "sbyte", "char", "decimal", "double", "float", "int", "uint", 
			"long", "ulong", "short", "ushort", "string", "object", "void",
			"Boolean", "Byte", "SByte", "Char", "Decimal", "Double", "Single", "Int32", "UInt32",
			"Int64", "UInt64", "Int16", "UInt16", "String", "Object", "Void",
			"List", "Dictionary", "IList", "IDictionary", "IEnumerable", "ICollection",
			"Task", "CancellationToken", "DateTime", "TimeSpan", "Guid"
		}
		return type_name in primitives

	def _get_identifier_name(self, node):
		name_node = next((c for c in node.children if c.type == "identifier"), None)
		return name_node.text.decode() if name_node else None

	def _get_identifier_name_cs(self, node):
		if node.type == "class_declaration":
			found_class_keyword = False
			for child in node.children:
				if child.type == "class":
					found_class_keyword = True
				elif found_class_keyword and child.type == "identifier":
					return child.text.decode()
		elif node.type == "interface_declaration":
			found_interface_keyword = False
			for child in node.children:
				if child.type == "interface":
					found_interface_keyword = True
				elif found_interface_keyword and child.type == "identifier":
					return child.text.decode()
		elif node.type == "struct_declaration":
			found_struct_keyword = False
			for child in node.children:
				if child.type == "struct":
					found_struct_keyword = True
				elif found_struct_keyword and child.type == "identifier":
					return child.text.decode()
		name_node = next((c for c in node.children if c.type == "identifier"), None)
		return name_node.text.decode() if name_node else None

	def _get_type_name(self, node):
		"""Get type name from a type node."""
		if node.type == "identifier":
			return node.text.decode()
		elif node.type == "generic_name":
			type_node = next((c for c in node.children if c.type == "identifier"), None)
			return type_node.text.decode() if type_node else None
		elif node.type == "predefined_type":
			return node.text.decode()
		return None

	def _find_containing_class(self, node, top_level_nodes):
		current = node.parent
		while current:
			if current.type in ["class_declaration", "interface_declaration", "struct_declaration", "enum_declaration", "record_declaration", "delegate_declaration"]:
				class_name = self._get_identifier_name_cs(current)
				if class_name and class_name in top_level_nodes:
					return class_name
			current = current.parent
		return None

def analyze_csharp_file(file_path: str, content: str, repo_path: str = None) -> Tuple[List[Node], List[CallRelationship]]:
	analyzer = TreeSitterCSharpAnalyzer(file_path, content, repo_path)
	return analyzer.nodes, analyzer.call_relationships

class TreeSitterJavaAnalyzer:
	def __init__(self, file_path: str, content: str, repo_path: str = None):
		self.file_path = Path(file_path)
		self.content = content
		self.repo_path = repo_path or ""
		self.nodes: List[Node] = []
		self.call_relationships: List[CallRelationship] = []
		self._analyze()

	def _get_module_path(self) -> str:
		if self.repo_path:
			try:
				rel_path = os.path.relpath(str(self.file_path), self.repo_path)
			except ValueError:
				rel_path = str(self.file_path)
		else:
			rel_path = str(self.file_path)

		for ext in ['.java']:
			if rel_path.endswith(ext):
				rel_path = rel_path[:-len(ext)]
				break
		return rel_path.replace('/', '.').replace('\\', '.')

	def _get_relative_path(self) -> str:
		"""Get relative path from repo root."""
		if self.repo_path:
			try:
				return os.path.relpath(str(self.file_path), self.repo_path)
			except ValueError:
				return str(self.file_path)
		else:
			return str(self.file_path)

	def _get_component_id(self, name: str, parent_class: str = None) -> str:
		rel_path = self._get_relative_path()
		if parent_class:
			return f"{rel_path}::{parent_class}.{name}"
		else:
			return f"{rel_path}::{name}"

	def _analyze(self):
		language_capsule = tree_sitter_java.language()
		java_language = Language(language_capsule)
		parser = Parser(java_language)
		tree = parser.parse(bytes(self.content, "utf8"))
		root = tree.root_node
		lines = self.content.splitlines()

		top_level_nodes = {}

		self._extract_nodes(root, top_level_nodes, lines)

		self._extract_relationships(root, top_level_nodes)

	def _extract_nodes(self, node, top_level_nodes, lines):
		node_type = None
		node_name = None

		if node.type == "class_declaration":
			is_abstract = any(c.type == "modifier" and c.text.decode() == "abstract" for c in node.children)
			node_type = "abstract class" if is_abstract else "class"
			name_node = next((c for c in node.children if c.type == "identifier"), None)
			node_name = name_node.text.decode() if name_node else None
		elif node.type == "interface_declaration":
			node_type = "interface"
			name_node = next((c for c in node.children if c.type == "identifier"), None)
			node_name = name_node.text.decode() if name_node else None
		elif node.type == "enum_declaration":
			node_type = "enum"
			name_node = next((c for c in node.children if c.type == "identifier"), None)
			node_name = name_node.text.decode() if name_node else None
		elif node.type == "record_declaration":
			node_type = "record"
			name_node = next((c for c in node.children if c.type == "identifier"), None)
			node_name = name_node.text.decode() if name_node else None
		elif node.type == "annotation_type_declaration":
			node_type = "annotation"
			name_node = next((c for c in node.children if c.type == "identifier"), None)
			node_name = name_node.text.decode() if name_node else None
		elif node.type == "method_declaration":
			node_type = "method"
			name_node = next((c for c in node.children if c.type == "identifier"), None)
			if name_node:
				method_name = name_node.text.decode()
				containing_class = self._find_containing_class_name(node)
				if containing_class:
					node_name = f"{containing_class}.{method_name}"
				else:
					node_name = method_name

		if node_type and node_name:
			component_id = self._get_component_id(node_name)
			relative_path = self._get_relative_path()
			node_obj = Node(
				id=component_id,
				name=node_name,
				component_type=node_type,
				file_path=str(self.file_path),
				relative_path=relative_path,
				source_code="\n".join(lines[node.start_point[0]:node.end_point[0]+1]),
				start_line=node.start_point[0]+1,
				end_line=node.end_point[0]+1,
				has_docstring=False,
				docstring="",
				parameters=None,
				node_type=node_type,
				base_classes=None,
				class_name=None,
				display_name=f"{node_type} {node_name}",
				component_id=component_id
			)
			self.nodes.append(node_obj)
			top_level_nodes[node_name] = node_obj

		# Recursively process children
		for child in node.children:
			self._extract_nodes(child, top_level_nodes, lines)

	def _extract_relationships(self, node, top_level_nodes):
		# 1. Inheritance: Class extends another class
		if node.type == "class_declaration":
			class_name = self._get_identifier_name(node)
			children_types = [c.type for c in node.children]

			extends_node = next((c for c in node.children if c.type == "superclass"), None)
			if extends_node:
				base_class_name = self._get_type_name(extends_node)
				if class_name and base_class_name and not self._is_primitive_type(base_class_name):
					caller_id = self._get_component_id(class_name)
					callee_id = self._get_component_id(base_class_name)  
					self.call_relationships.append(CallRelationship(
						caller=caller_id,
						callee=callee_id,  
						call_line=node.start_point[0]+1,
						is_resolved=False  
					))
			else:
				logger.debug(f"   No superclass found for {class_name}")

		# 2. Interface Implementation: Class/enum/record implements interface
		if node.type in ["class_declaration", "enum_declaration", "record_declaration"]:
			implementer_name = self._get_identifier_name(node)
			implements_node = next((c for c in node.children if c.type == "super_interfaces"), None)
			if implements_node and implementer_name:
				for child in implements_node.children:
					if child.type == "type_list":
						for type_child in child.children:
							if type_child.type in ["type_identifier", "generic_type"]:
								interface_name = self._get_type_name(type_child)
								if interface_name and not self._is_primitive_type(interface_name):
									caller_id = self._get_component_id(implementer_name)
									callee_id = self._get_component_id(interface_name)  
									self.call_relationships.append(CallRelationship(
										caller=caller_id,
										callee=callee_id,  
										call_line=node.start_point[0]+1,
										is_resolved=False
									))

		# 3. Field Type Use: Class has field of another class/interface type
		if node.type == "field_declaration":
			containing_class = self._find_containing_class(node, top_level_nodes)
			type_node = next((c for c in node.children if c.type in ["type_identifier", "generic_type"]), None)
			if containing_class and type_node:
				field_type_name = self._get_type_name(type_node)
				if field_type_name and not self._is_primitive_type(field_type_name):
					self.call_relationships.append(CallRelationship(
						caller=containing_class,
						callee=field_type_name,  
						call_line=node.start_point[0]+1,
						is_resolved=False
					))

		# 4. Method Calls: Method calls on objects
		if node.type == "method_invocation":
			containing_class = self._find_containing_class(node, top_level_nodes)
			containing_method = self._find_containing_method(node)
			if containing_class:
				object_name = None
				method_name = None

				if node.children:
					first_child = node.children[0]
					if first_child.type == "identifier":
						object_name = first_child.text.decode()
						if len(node.children) >= 3:  
							method_child = node.children[2]
							if method_child.type == "identifier":
								method_name = method_child.text.decode()

				if object_name and method_name:
					target_type = None

					caller_id = containing_method or containing_class

					if object_name in top_level_nodes:
						target_type = object_name
					else:
						target_type = self._find_variable_type(node, object_name, top_level_nodes)

					if target_type and not self._is_primitive_type(target_type):
						self.call_relationships.append(CallRelationship(
							caller=caller_id,
							callee=target_type,
							call_line=node.start_point[0]+1,
							is_resolved=False
						))

		# 5. Object Creation
		if node.type == "object_creation_expression":
			containing_class = self._find_containing_class(node, top_level_nodes)
			type_node = next((c for c in node.children if c.type in ["type_identifier", "generic_type"]), None)
			if containing_class and type_node:
				created_type = self._get_type_name(type_node)
				if created_type and not self._is_primitive_type(created_type):
					self.call_relationships.append(CallRelationship(
						caller=containing_class,
						callee=created_type,
						call_line=node.start_point[0]+1,
						is_resolved=False
					))

		# Recursively process children
		for child in node.children:
			self._extract_relationships(child, top_level_nodes)

	def _is_primitive_type(self, type_name: str) -> bool:
		"""Check if type is a Java primitive or common built-in type."""
		primitives = {
			"boolean", "byte", "char", "double", "float", "int", "long", "short",
			"Boolean", "Byte", "Character", "Double", "Float", "Integer", "Long", "Short",
			"String", "Object", "List", "Set", "Map", "Collection", "Optional",
			"void", "Void"
		}
		return type_name in primitives

	def _get_identifier_name(self, node):
		"""Get identifier name from a node."""
		name_node = next((c for c in node.children if c.type == "identifier"), None)
		return name_node.text.decode() if name_node else None

	def _get_type_name(self, node):
		"""Get type name from a type node."""
		if node.type == "type_identifier":
			return node.text.decode()
		elif node.type == "generic_type":
			type_node = next((c for c in node.children if c.type == "type_identifier"), None)
			return type_node.text.decode() if type_node else None
		elif node.type == "superclass":
			type_node = next((c for c in node.children if c.type == "type_identifier"), None)
			return type_node.text.decode() if type_node else None
		return None

	def _find_containing_class(self, node, top_level_nodes):
		current = node.parent
		while current:
			if current.type in ["class_declaration", "interface_declaration", "enum_declaration", "record_declaration", "annotation_type_declaration"]:
				class_name = self._get_identifier_name(current)
				if class_name and class_name in top_level_nodes:
					return self._get_component_id(class_name)  
			current = current.parent
		return None

	def _find_variable_type(self, node, variable_name, top_level_nodes):
		method_node = node.parent
		while method_node and method_node.type != "method_declaration":
			method_node = method_node.parent

		if method_node:
			for child in method_node.children:
				if child.type == "block":
					variable_type = self._search_variable_declaration(child, variable_name)
					if variable_type:
						return variable_type

		class_node = node.parent
		while class_node and class_node.type != "class_declaration":
			class_node = class_node.parent

		if class_node:
			for child in class_node.children:
				if child.type == "class_body":
					for body_child in child.children:
						if body_child.type == "field_declaration":
							identifier_node = None
							type_node = None
							for field_child in body_child.children:
								if field_child.type in ["type_identifier", "generic_type"]:
									type_node = field_child
								elif field_child.type == "variable_declarator":
									identifier_node = next((c for c in field_child.children if c.type == "identifier"), None)

							if identifier_node and type_node and identifier_node.text.decode() == variable_name:
								field_type = self._get_type_name(type_node)
								return field_type

		return None

	def _search_variable_declaration(self, block_node, variable_name):
		for child in block_node.children:
			if child.type == "local_variable_declaration":
				type_node = None
				identifier_node = None
				for decl_child in child.children:
					if decl_child.type in ["type_identifier", "generic_type"]:
						type_node = decl_child
					elif decl_child.type == "variable_declarator":
						identifier_node = next((c for c in decl_child.children if c.type == "identifier"), None)

				if identifier_node and type_node and identifier_node.text.decode() == variable_name:
					return self._get_type_name(type_node)

			elif child.type == "block":
				result = self._search_variable_declaration(child, variable_name)
				if result:
					return result

		return None

	def _find_containing_class_name(self, node):
		current = node.parent
		while current:
			if current.type in ["class_declaration", "interface_declaration", "enum_declaration", "record_declaration"]:
				name_node = next((c for c in current.children if c.type == "identifier"), None)
				if name_node:
					return name_node.text.decode()
			current = current.parent
		return None

	def _find_containing_method(self, node):
		current = node.parent
		while current:
			if current.type == "method_declaration":
				method_name = self._get_identifier_name(current)
				class_name = self._find_containing_class_name(current)
				if method_name and class_name:
					return self._get_component_id(f"{class_name}.{method_name}")
			current = current.parent
		return None

def analyze_java_file(file_path: str, content: str, repo_path: str = None) -> Tuple[List[Node], List[CallRelationship]]:
	analyzer = TreeSitterJavaAnalyzer(file_path, content, repo_path)
	return analyzer.nodes, analyzer.call_relationships

class TreeSitterJSAnalyzer:
    def __init__(self, file_path: str, content: str, repo_path: str = None):
        self.file_path = Path(file_path)
        self.content = content
        self.repo_path = repo_path or ""
        self.nodes: List[Node] = []
        self.call_relationships: List[CallRelationship] = []

        self.top_level_nodes = {}

        self.seen_relationships = set()

        try:
            language_capsule = tree_sitter_javascript.language()
            self.js_language = Language(language_capsule)
            self.parser = Parser(self.js_language)

        except Exception as e:
            logger.error(f"Failed to initialize JavaScript parser: {e}")
            logger.error(f"Traceback: {traceback.format_exc()}")
            self.parser = None
            self.js_language = None


    def _add_relationship(self, relationship: CallRelationship) -> bool:
        rel_key = (relationship.caller, relationship.callee, relationship.call_line)

        if rel_key not in self.seen_relationships:
            self.seen_relationships.add(rel_key)
            self.call_relationships.append(relationship)
            return True
        return False

    def analyze(self) -> None:
        if self.parser is None:
            logger.warning(f"Skipping {self.file_path} - parser initialization failed")
            return

        try:
            tree = self.parser.parse(bytes(self.content, "utf8"))
            root_node = tree.root_node

            logger.debug(f"Parsed AST with root node type: {root_node.type}")

            self._extract_functions(root_node)
            self._extract_call_relationships(root_node)

            logger.debug(
                f"Analysis complete: {len(self.nodes)} nodes, {len(self.call_relationships)} relationships"
            )

        except Exception as e:
            logger.error(f"Error analyzing JavaScript file {self.file_path}: {e}", exc_info=True)

    def _get_module_path(self) -> str:
        if self.repo_path:
            try:
                rel_path = os.path.relpath(str(self.file_path), self.repo_path)
            except ValueError:
                rel_path = str(self.file_path)
        else:
            rel_path = str(self.file_path)

        for ext in ['.js', '.ts', '.jsx', '.tsx', '.mjs', '.cjs']:
            if rel_path.endswith(ext):
                rel_path = rel_path[:-len(ext)]
                break
        return rel_path.replace('/', '.').replace('\\', '.')

    def _get_relative_path(self) -> str:
        if self.repo_path:
            try:
                return os.path.relpath(str(self.file_path), self.repo_path)
            except ValueError:
                return str(self.file_path)
        else:
            return str(self.file_path)

    def _get_component_id(self, name: str, class_name: str = None, is_method: bool = False) -> str:
        relative_path = self._get_relative_path()

        if is_method and class_name:
            return f"{relative_path}::{class_name}.{name}"
        elif class_name and not is_method:
            return f"{relative_path}::{name}"
        else:
            return f"{relative_path}::{name}"

    def _find_containing_class(self, node) -> Optional[str]:
        parent = node.parent
        while parent:
            if parent.type in ["class_declaration", "abstract_class_declaration", "interface_declaration"]:
                name_node = self._find_child_by_type(parent, "type_identifier")
                if not name_node:
                    name_node = self._find_child_by_type(parent, "identifier")
                if name_node:
                    return self._get_node_text(name_node)
            parent = parent.parent
        return None

    def _extract_functions(self, node) -> None:
        self._traverse_for_functions(node)
        self.nodes.sort(key=lambda n: n.start_line)

    def _traverse_for_functions(self, node) -> None:
        if node.type in ["class_declaration", "abstract_class_declaration", "interface_declaration"]:
            cls = self._extract_class_declaration(node)
            if cls:
                self.nodes.append(cls)
                self.top_level_nodes[cls.name] = cls

                self._extract_methods_from_class(node, cls.name)

        elif node.type == "function_declaration":
            containing_class = self._find_containing_class(node)
            if containing_class is None:
                func = self._extract_function_declaration(node)
                if func and self._should_include_function(func):
                    self.nodes.append(func)
                    self.top_level_nodes[func.name] = func
        elif node.type == "generator_function_declaration":
            containing_class = self._find_containing_class(node)
            if containing_class is None:
                func = self._extract_function_declaration(node)
                if func and self._should_include_function(func):
                    self.nodes.append(func)
                    self.top_level_nodes[func.name] = func
        elif node.type == "export_statement":
            func = self._extract_exported_function(node)
            if func and self._should_include_function(func):
                self.nodes.append(func)
                self.top_level_nodes[func.name] = func
        elif node.type == "lexical_declaration":
            containing_class = self._find_containing_class(node)
            if containing_class is None:
                func = self._extract_arrow_function_from_declaration(node)
                if func and self._should_include_function(func):
                    self.nodes.append(func)
                    self.top_level_nodes[func.name] = func

        for child in node.children:
            self._traverse_for_functions(child)

    def _extract_methods_from_class(self, class_node, class_name: str) -> None:
        class_body = self._find_child_by_type(class_node, "class_body")
        if not class_body:
            return

        for child in class_body.children:
            if child.type == "method_definition":
                method_name = self._get_method_name(child)
                if method_name:
                    method_key = f"{self._get_relative_path()}::{class_name}.{method_name}"
                    method_node = self._create_method_node(child, method_name, class_name)
                    if method_node:
                        self.top_level_nodes[method_key] = method_node
            elif child.type == "field_definition":
                # Handle arrow function properties
                field_name = self._get_field_name(child)
                if field_name and self._is_arrow_function_field(child):
                    method_key = f"{self._get_relative_path()}::{class_name}.{field_name}"
                    method_node = self._create_method_node(child, field_name, class_name)
                    if method_node:
                        self.top_level_nodes[method_key] = method_node

    def _get_method_name(self, method_node) -> Optional[str]:
        """Get method name from method_definition node."""
        if method_node.type != "method_definition":
            return None

        for child in method_node.children:
            if child.type == "property_identifier":
                return self._get_node_text(child)
        return None

    def _get_field_name(self, field_node) -> Optional[str]:
        """Get field name from field_definition node."""
        if field_node.type != "field_definition":
            return None

        for child in field_node.children:
            if child.type == "property_identifier":
                return self._get_node_text(child)
        return None

    def _is_arrow_function_field(self, field_node) -> bool:
        """Check if field_definition contains an arrow function."""
        for child in field_node.children:
            if child.type == "arrow_function":
                return True
        return False

    def _create_method_node(self, node, method_name: str, class_name: str) -> Optional[Node]:
        """Create a method node for relationship mapping."""
        try:
            line_start = node.start_point[0] + 1
            line_end = node.end_point[0] + 1
            component_id = self._get_component_id(method_name, class_name, is_method=True)
            relative_path = self._get_relative_path()

            return Node(
                id=component_id,
                name=method_name,
                component_type="method",
                file_path=str(self.file_path),
                relative_path=relative_path,
                source_code="\n".join(self.content.splitlines()[line_start - 1 : line_end]),
                start_line=line_start,
                end_line=line_end,
                has_docstring=False,
                docstring="",
                parameters=None,
                node_type="method",
                base_classes=None,
                class_name=class_name,
                display_name=f"method {method_name}",
                component_id=component_id
            )
        except Exception as e:
            logger.debug(f"Error creating method node for {method_name}: {e}")
            return None

    def _extract_class_declaration(self, node) -> Optional[Node]:
        """Extract class/abstract class/interface declaration."""
        try:
            name_node = self._find_child_by_type(node, "type_identifier")
            if not name_node:
                name_node = self._find_child_by_type(node, "identifier")
            if not name_node:
                return None
            name = self._get_node_text(name_node)
            line_start = node.start_point[0] + 1
            line_end = node.end_point[0] + 1
            docstring = None
            base_classes = []
            heritage_node = self._find_child_by_type(node, "class_heritage")
            if heritage_node:
                for child in heritage_node.children:
                    if child.type in ["identifier", "type_identifier"]:
                        base_classes.append(self._get_node_text(child))
            code_snippet = "\n".join(self.content.splitlines()[line_start - 1 : line_end])

            if node.type == "abstract_class_declaration":
                node_type = "abstract class"
                display_name = f"abstract class {name}"
            elif node.type == "interface_declaration":
                node_type = "interface"
                display_name = f"interface {name}"
            else:
                node_type = "class"
                display_name = f"class {name}"

            component_id = self._get_component_id(name, is_method=False)
            relative_path = self._get_relative_path()

            return Node(
                id=component_id,
                name=name,
                component_type=node_type,
                file_path=str(self.file_path),
                relative_path=relative_path,
                source_code=code_snippet,
                start_line=line_start,
                end_line=line_end,
                has_docstring=bool(docstring),
                docstring=docstring or "",
                parameters=None,
                node_type=node_type,
                base_classes=base_classes if base_classes else None,
                class_name=None,
                display_name=display_name,
                component_id=component_id,
            )
        except Exception:
            return None

    def _extract_function_declaration(self, node) -> Optional[Node]:
        try:
            name_node = self._find_child_by_type(node, "identifier")
            if not name_node:
                return None

            func_name = self._get_node_text(name_node)
            line_start = node.start_point[0] + 1
            line_end = node.end_point[0] + 1
            parameters = self._extract_parameters(node)
            code_snippet = self._get_node_text(node)

            # Check for async and generator from code snippet
            is_async = "async function" in code_snippet
            is_generator = "function*" in code_snippet or "*" in func_name

            if is_async and is_generator:
                display_name = f"async generator {func_name}"
            elif is_async:
                display_name = f"async function {func_name}"
            elif is_generator:
                display_name = f"generator function {func_name}"
            else:
                display_name = f"function {func_name}"

            component_id = self._get_component_id(func_name, is_method=False)
            relative_path = self._get_relative_path()

            return Node(
                id=component_id,
                name=func_name,
                component_type="function",
                file_path=str(self.file_path),
                relative_path=relative_path,
                source_code=code_snippet,
                start_line=line_start,
                end_line=line_end,
                has_docstring=False,
                docstring="",
                parameters=parameters,
                node_type="function",
                base_classes=None,
                class_name=None,
                display_name=display_name,
                component_id=component_id,
            )
        except Exception as e:
            logger.debug(f"Error extracting function declaration: {e}")
            return None
    def _extract_exported_function(self, node) -> Optional[Node]:
        """Extract export function or export default function"""
        try:
            func_decl = self._find_child_by_type(node, "function_declaration")
            if func_decl:
                func = self._extract_function_declaration(func_decl)
                if func:
                    export_text = self._get_node_text(node)
                    if "export default" in export_text and "function (" in export_text:
                        func.name = "default"
                return func
        except Exception as e:
            logger.debug(f"Error extracting exported function: {e}")
        return None

    def _extract_arrow_function_from_declaration(self, node) -> Optional[Node]:
        """Extract arrow function or function expression from const/let/var declarations."""
        try:
            for child in node.children:
                if child.type == "variable_declarator":
                    name_node = self._find_child_by_type(child, "identifier")
                    func_node = self._find_child_by_type(
                        child, "arrow_function"
                    ) or self._find_child_by_type(child, "function_expression")

                    if name_node and func_node:
                        func_name = self._get_node_text(name_node)
                        line_start = func_node.start_point[0] + 1
                        line_end = func_node.end_point[0] + 1
                        parameters = self._extract_parameters(func_node)
                        code_snippet = self._get_node_text(child)

                        component_id = self._get_component_id(func_name, is_method=False)
                        relative_path = self._get_relative_path()

                        return Node(
                            id=component_id,
                            name=func_name,
                            component_type="function",
                            file_path=str(self.file_path),
                            relative_path=relative_path,
                            source_code=code_snippet,
                            start_line=line_start,
                            end_line=line_end,
                            has_docstring=False,
                            docstring="",
                            parameters=parameters,
                            node_type="function",
                            base_classes=None,
                            class_name=None,
                            display_name=f"function {func_name}",
                            component_id=component_id,
                        )
            return None
        except Exception as e:
            logger.debug(f"Error extracting function from declaration: {e}")
        return None

    def _should_include_function(self, func: Node) -> bool:
        excluded_names = {}

        if func.name.lower() in excluded_names:
            logger.debug(f"Skipping excluded function: {func.name}")
            return False

        return True

    def _extract_parameters(self, node) -> List[str]:
        parameters = []
        params_node = self._find_child_by_type(node, "formal_parameters")
        if params_node:
            for child in params_node.children:
                if child.type == "identifier":
                    parameters.append(self._get_node_text(child))
        return parameters

    def _extract_call_relationships(self, node) -> None:
        current_top_level = None
        self._traverse_for_calls(node, current_top_level)

    def _traverse_for_calls(self, node, current_top_level) -> None:
        if current_top_level:
            self._extract_jsdoc_type_dependencies(node, current_top_level)

        if node.type in ["class_declaration", "abstract_class_declaration", "interface_declaration"]:
            name_node = self._find_child_by_type(node, "type_identifier") or self._find_child_by_type(node, "identifier")
            if name_node:
                current_top_level = self._get_node_text(name_node)

                heritage_node = self._find_child_by_type(node, "class_heritage")
                if heritage_node:
                    for child in heritage_node.children:
                        if child.type in ["identifier", "type_identifier"]:
                            base_class = self._get_node_text(child)
                            caller_id = self._get_component_id(current_top_level)
                            callee_id = f"{self._get_relative_path()}::{base_class}"
                            inheritance_rel = CallRelationship(
                                caller=caller_id,
                                callee=callee_id,
                                call_line=node.start_point[0] + 1,
                                is_resolved=False
                            )
                            self._add_relationship(inheritance_rel)

        elif node.type == "function_declaration":
            name_node = self._find_child_by_type(node, "identifier")
            if name_node:
                current_top_level = self._get_node_text(name_node)
        elif node.type == "generator_function_declaration":
            name_node = self._find_child_by_type(node, "identifier")
            if name_node:
                current_top_level = self._get_node_text(name_node)
        elif node.type == "lexical_declaration":
            for child in node.children:
                if child.type == "variable_declarator":
                    name_node = self._find_child_by_type(child, "identifier")
                    func_node = self._find_child_by_type(child, "arrow_function") or self._find_child_by_type(child, "function_expression")
                    if name_node and func_node:
                        current_top_level = self._get_node_text(name_node)

        if node.type == "call_expression" and current_top_level:
            call_info = self._extract_call_from_node(node, current_top_level)
            if call_info:
                self._add_relationship(call_info)

        elif node.type == "await_expression" and current_top_level:
            call_expr = self._find_child_by_type(node, "call_expression")
            if call_expr:
                call_info = self._extract_call_from_node(call_expr, current_top_level)
                if call_info:
                    self._add_relationship(call_info)

        elif node.type == "new_expression" and current_top_level:
            callee_name = self._extract_callee_name(node)
            if callee_name:
                call_info = CallRelationship(
                    caller=f"{self._get_relative_path()}::{current_top_level}",
                    callee=f"{self._get_relative_path()}::{callee_name}",
                    call_line=node.start_point[0] + 1,
                    is_resolved=False
                )
                self._add_relationship(call_info)

        for child in node.children:
            self._traverse_for_calls(child, current_top_level)

    def _extract_call_from_node(self, node, caller_name: str) -> Optional[CallRelationship]:
        """Extract call relationship from a call_expression node."""
        try:
            call_line = node.start_point[0] + 1
            callee_name = self._extract_callee_name(node)

            if not callee_name:
                return None

            call_text = self._get_node_text(node)
            is_method_call = "this." in call_text or "super." in call_text

            caller_id = f"{self._get_relative_path()}::{caller_name}"

            if is_method_call:
                current_class = None
                for node_key, node_obj in self.top_level_nodes.items():
                    if node_obj.component_type == "class" and caller_name in node_key:
                        current_class = node_obj.name
                        break

                if current_class:
                    method_key = f"{self._get_relative_path()}::{current_class}.{callee_name}"
                    if method_key in self.top_level_nodes:
                        return None

            callee_id = f"{self._get_relative_path()}::{callee_name}"
            if callee_name in self.top_level_nodes:
                return CallRelationship(
                    caller=caller_id,
                    callee=callee_id,
                    call_line=call_line,
                    is_resolved=True,
                )

            return CallRelationship(
                caller=caller_id,
                callee=callee_id,
                call_line=call_line,
                is_resolved=False,
            )

        except Exception as e:
            logger.debug(f"Error extracting call relationship: {e}")
            return None

    def _extract_jsdoc_type_dependencies(self, node, caller_name: str) -> None:
        """Extract type dependencies from JSDoc comments."""
        try:
            if hasattr(node, 'prev_sibling') and node.prev_sibling:
                prev = node.prev_sibling
                if prev.type == "comment":
                    comment_text = self._get_node_text(prev)
                    self._parse_jsdoc_types(comment_text, caller_name, node.start_point[0] + 1)

            for child in node.children:
                if child.type == "comment":
                    comment_text = self._get_node_text(child)
                    self._parse_jsdoc_types(comment_text, caller_name, node.start_point[0] + 1)

        except Exception as e:
            logger.debug(f"Error extracting JSDoc dependencies: {e}")

    def _parse_jsdoc_types(self, comment_text: str, caller_name: str, line_number: int) -> None:
        """Parse JSDoc comment text and extract type references."""
        import re
        try:
            type_patterns = [
                r'@param\s*\{([^}]+)\}',     # @param {Type}
                r'@returns?\s*\{([^}]+)\}',  # @return {Type} or @returns {Type}
                r'@type\s*\{([^}]+)\}',      # @type {Type}
                r'@typedef\s*\{[^}]*\}\s*(\w+)', # @typedef {Object} TypeName
                r'@interface\s+(\w+)',       # @interface InterfaceName
            ]

            for pattern in type_patterns:
                matches = re.findall(pattern, comment_text)
                for match in matches:
                    type_name = match.strip()

                    base_types = self._extract_base_types_from_jsdoc(type_name)

                    for base_type in base_types:
                        if base_type and not self._is_builtin_type_js(base_type):
                            caller_id = f"{self._get_relative_path()}::{caller_name}"
                            callee_id = f"{self._get_relative_path()}::{base_type}"

                            type_rel = CallRelationship(
                                caller=caller_id,
                                callee=callee_id,
                                call_line=line_number,
                                is_resolved=False 
                            )

                            if self._add_relationship(type_rel):
                                pass

        except Exception as e:
            logger.debug(f"Error parsing JSDoc types: {e}")

    def _extract_base_types_from_jsdoc(self, type_str: str) -> list:
        import re
        type_str = type_str.strip()

        base_types = []

        main_type_match = re.match(r'^(\w+)', type_str)
        if main_type_match:
            base_types.append(main_type_match.group(1))

        generic_matches = re.findall(r'<([^<>]+)>', type_str)
        for generic in generic_matches:
            subtypes = re.findall(r'\b(\w+)\b', generic)
            base_types.extend(subtypes)

        if '|' in type_str:
            union_types = type_str.split('|')
            for union_type in union_types:
                clean_type = re.match(r'\b(\w+)\b', union_type.strip())
                if clean_type:
                    base_types.append(clean_type.group(1))

        return base_types

    def _is_builtin_type_js(self, name: str) -> bool:
        """Check if type name is a JavaScript/JSDoc built-in type."""
        builtin_types = {
            # JavaScript primitive types
            "string", "number", "boolean", "object", "undefined", "null", "void", "any",

            # Global JavaScript types
            "Array", "Promise", "Date", "RegExp", "Error", "Map", "Set", "WeakMap", "WeakSet",
            "Function", "Object", "String", "Number", "Boolean", "Symbol", "BigInt",

            "Element", "HTMLElement", "Document", "Window", "Event", "EventTarget", "Node",
            "Response", "Request", "Headers", "URL", "URLSearchParams", "FormData", "Blob", "File",

            # Common JSDoc generic parameters
            "T", "U", "V", "K", "P", "R", "E"
        }
        return name in builtin_types

    def _extract_callee_name(self, call_node) -> Optional[str]:
        if not call_node.children:
            return None

        callee_node = call_node.children[0]

        if callee_node.type == "identifier":
            return self._get_node_text(callee_node)
        elif callee_node.type == "member_expression":
            property_node = self._find_child_by_type(callee_node, "property_identifier")
            if property_node:
                return self._get_node_text(property_node)

            computed_property = self._find_child_by_type(callee_node, "computed_property_name")
            if computed_property:
                for child in computed_property.children:
                    if child.type == "identifier":
                        return self._get_node_text(child)
        elif callee_node.type == "super":
            return "super"
        elif callee_node.type == "this":
            return "this"

        return None

    def _find_child_by_type(self, node, node_type: str):
        """Find first child node of specified type."""
        for child in node.children:
            if child.type == node_type:
                return child
        return None

    def _get_node_text(self, node) -> str:
        start_byte = node.start_byte
        end_byte = node.end_byte
        return self.content.encode("utf8")[start_byte:end_byte].decode("utf8")

    def _find_containing_class_name(self, method_node) -> Optional[str]:
        current = method_node.parent
        while current:
            if current.type == "class_declaration":
                name_node = self._find_child_by_type(current, "identifier")
                if name_node:
                    return self._get_node_text(name_node)
            current = current.parent
        return None

    def _extract_assignment_name(self, node) -> Optional[str]:
        if node.type == "identifier":
            return self._get_node_text(node)
        elif node.type == "member_expression":
            property_node = self._find_child_by_type(node, "property_identifier")
            if property_node:
                return self._get_node_text(property_node)
        return None

def analyze_javascript_file_treesitter(
    file_path: str, content: str, repo_path: str = None
) -> Tuple[List[Node], List[CallRelationship]]:
    """Analyze a JavaScript file using tree-sitter."""
    try:
        logger.debug(f"Tree-sitter JS analysis for {file_path}")
        analyzer = TreeSitterJSAnalyzer(file_path, content, repo_path)
        analyzer.analyze()
        logger.debug(
            f"Found {len(analyzer.nodes)} top-level nodes, {len(analyzer.call_relationships)} calls"
        )
        return analyzer.nodes, analyzer.call_relationships
    except Exception as e:
        logger.error(f"Error in tree-sitter JS analysis for {file_path}: {e}", exc_info=True)
        return [], []

class TreeSitterKotlinAnalyzer:
    def __init__(self, file_path: str, content: str, repo_path: Optional[str] = None):
        self.file_path = Path(file_path)
        self.content = content
        self.repo_path = repo_path or ""
        self.nodes: List[Node] = []
        self.call_relationships: List[CallRelationship] = []
        self._analyze()

    def _get_module_path(self) -> str:
        if self.repo_path:
            try:
                rel_path = os.path.relpath(str(self.file_path), self.repo_path)
            except ValueError:
                rel_path = str(self.file_path)
        else:
            rel_path = str(self.file_path)

        for ext in ['.kt', '.kts']:
            if rel_path.endswith(ext):
                rel_path = rel_path[:-len(ext)]
                break
        return rel_path.replace('/', '.').replace('\\', '.')

    def _get_relative_path(self) -> str:
        """Get relative path from repo root."""
        if self.repo_path:
            try:
                return os.path.relpath(str(self.file_path), self.repo_path)
            except ValueError:
                return str(self.file_path)
        else:
            return str(self.file_path)

    def _get_component_id(self, name: str, parent_class: Optional[str] = None) -> str:
        rel_path = self._get_relative_path()
        if parent_class:
            return f"{rel_path}::{parent_class}.{name}"
        else:
            return f"{rel_path}::{name}"

    def _analyze(self):
        try:
            language_capsule = tree_sitter_kotlin.language()
            kotlin_language = Language(language_capsule)
            parser = Parser(kotlin_language)
            tree = parser.parse(bytes(self.content, "utf8"))
            root = tree.root_node
            lines = self.content.splitlines()

            top_level_nodes = {}

            self._extract_nodes(root, top_level_nodes, lines)
            self._extract_relationships(root, top_level_nodes)
        except Exception as e:
            logger.error(f"Error parsing Kotlin file {self.file_path}: {e}")

    def _extract_nodes(self, node, top_level_nodes, lines):
        node_type = None
        node_name = None

        if node.type == "class_declaration":
            is_interface = any(c.type == "interface" for c in node.children)

            if is_interface:
                node_type = "interface"
            else:
                modifiers = self._get_class_modifiers(node)
                if "abstract" in modifiers:
                    node_type = "abstract class"
                elif "data" in modifiers:
                    node_type = "data class"
                elif "enum" in modifiers:
                    node_type = "enum class"
                elif "annotation" in modifiers:
                    node_type = "annotation class"
                else:
                    node_type = "class"

            name_node = next((c for c in node.children if c.type == "identifier"), None)
            node_name = name_node.text.decode() if name_node else None

        elif node.type == "object_declaration":
            node_type = "object"
            name_node = next((c for c in node.children if c.type == "identifier"), None)
            node_name = name_node.text.decode() if name_node else None

        elif node.type == "function_declaration":
            name_node = next((c for c in node.children if c.type == "identifier"), None)
            if name_node:
                method_name = name_node.text.decode()
                containing_class = self._find_containing_class_name(node)
                if containing_class:
                    node_type = "method"
                    node_name = f"{containing_class}.{method_name}"
                else:
                    node_type = "function"
                    node_name = method_name

        if node_type and node_name:
            component_id = self._get_component_id(node_name)
            relative_path = self._get_relative_path()

            # Extract docstring if present
            docstring = ""
            if node.prev_sibling and hasattr(node.prev_sibling, "type"):
                if node.prev_sibling.type in ("line_comment", "block_comment"):
                    docstring = node.prev_sibling.text.decode().strip()

            # Safely extract code lines
            start_line_idx = node.start_point[0]
            end_line_idx = node.end_point[0] + 1
            code_snippet = "\n".join(lines[start_line_idx:end_line_idx]) if start_line_idx < len(lines) else ""

            node_obj = Node(
                id=component_id,
                name=node_name,
                component_type=node_type,
                file_path=str(self.file_path),
                relative_path=relative_path,
                source_code=code_snippet,
                start_line=node.start_point[0]+1,
                end_line=node.end_point[0]+1,
                has_docstring=bool(docstring),
                docstring=docstring,
                parameters=None,
                node_type=node_type,
                base_classes=None,
                class_name=None,
                display_name=f"{node_type} {node_name}",
                component_id=component_id
            )
            self.nodes.append(node_obj)
            top_level_nodes[node_name] = node_obj

        for child in node.children:
            self._extract_nodes(child, top_level_nodes, lines)

    def _get_class_modifiers(self, class_node) -> set:
        """Extract class modifiers (abstract, data, enum, annotation, etc.)."""
        modifiers = set()
        modifiers_node = next((c for c in class_node.children if c.type == "modifiers"), None)
        if modifiers_node:
            for mod in modifiers_node.children:
                if mod.type in ("class_modifier", "inheritance_modifier", "visibility_modifier"):
                    for inner in mod.children:
                        modifiers.add(inner.type)
        return modifiers

    def _extract_relationships(self, node, top_level_nodes):
        # 1. Inheritance and Interface Implementation via delegation_specifiers
        if node.type == "class_declaration":
            class_name = self._get_identifier_name(node)
            delegation_specifiers = next(
                (c for c in node.children if c.type == "delegation_specifiers"), None
            )
            if delegation_specifiers and class_name:
                for spec in delegation_specifiers.children:
                    if spec.type == "delegation_specifier":
                        for child in spec.children:
                            type_name = None
                            if child.type == "constructor_invocation":
                                user_type = next(
                                    (c for c in child.children if c.type == "user_type"), None
                                )
                                if user_type:
                                    type_name = self._get_type_name(user_type)
                            elif child.type == "user_type":
                                type_name = self._get_type_name(child)

                            if type_name and not self._is_primitive_type(type_name):
                                caller_id = self._get_component_id(class_name)
                                callee_id = self._get_component_id(type_name)
                                self.call_relationships.append(CallRelationship(
                                    caller=caller_id,
                                    callee=callee_id,
                                    call_line=node.start_point[0]+1,
                                    is_resolved=False
                                ))

        # 2. Property Type Use (field types)
        if node.type == "property_declaration":
            containing_class = self._find_containing_class(node, top_level_nodes)
            var_decl = next((c for c in node.children if c.type == "variable_declaration"), None)
            if containing_class and var_decl:
                type_node = next(
                    (c for c in var_decl.children if c.type == "user_type"), None
                )
                if type_node:
                    prop_type_name = self._get_type_name(type_node)
                    if prop_type_name and not self._is_primitive_type(prop_type_name):
                        self.call_relationships.append(CallRelationship(
                            caller=containing_class,
                            callee=prop_type_name,
                            call_line=node.start_point[0]+1,
                            is_resolved=False
                        ))

        # 3. Constructor parameter type use
        if node.type == "class_parameter":
            containing_class_node = node.parent
            while containing_class_node and containing_class_node.type != "class_declaration":
                containing_class_node = containing_class_node.parent
            if containing_class_node:
                class_name = self._get_identifier_name(containing_class_node)
                if class_name and class_name in top_level_nodes:
                    type_node = next(
                        (c for c in node.children if c.type == "user_type"), None
                    )
                    if type_node:
                        param_type = self._get_type_name(type_node)
                        if param_type and not self._is_primitive_type(param_type):
                            caller_id = self._get_component_id(class_name)
                            self.call_relationships.append(CallRelationship(
                                caller=caller_id,
                                callee=param_type,
                                call_line=node.start_point[0]+1,
                                is_resolved=False
                            ))

        # 4. Method Calls / Function invocations
        if node.type == "call_expression":
            caller_id = self._find_containing_method(node) or self._find_containing_class(node, top_level_nodes)

            target_expr = next(
                (c for c in node.children if c.type in ["identifier", "navigation_expression"]), None
            )

            if target_expr and caller_id:
                if target_expr.type == "identifier":
                    callee_name = target_expr.text.decode()
                    if callee_name and callee_name[0].isupper() and not self._is_primitive_type(callee_name):
                        callee_id = self._get_component_id(callee_name)
                        self.call_relationships.append(CallRelationship(
                            caller=caller_id,
                            callee=callee_id,
                            call_line=node.start_point[0]+1,
                            is_resolved=False
                        ))
                    elif callee_name and not self._is_primitive_type(callee_name):
                        self.call_relationships.append(CallRelationship(
                            caller=caller_id,
                            callee=callee_name,
                            call_line=node.start_point[0]+1,
                            is_resolved=False
                        ))

                elif target_expr.type == "navigation_expression":
                    children = list(target_expr.children)
                    object_node = next(
                        (c for c in children if c.type == "identifier"), None
                    )
                    method_node = None
                    identifiers = [c for c in children if c.type == "identifier"]
                    if len(identifiers) >= 2:
                        object_node = identifiers[0]
                        method_node = identifiers[-1]
                    elif len(identifiers) == 1:
                        method_node = identifiers[0]
                        nav_child = next(
                            (c for c in children if c.type == "navigation_expression"), None
                        )
                        if nav_child:
                            object_node = self._get_root_identifier(nav_child)
                        else:
                            object_node = None

                    if object_node and method_node:
                        object_name = object_node.text.decode() if hasattr(object_node, 'text') else str(object_node)
                        method_name = method_node.text.decode()

                        target_type = None
                        if object_name in top_level_nodes:
                            target_type = object_name
                        else:
                            target_type = self._find_variable_type(node, object_name, top_level_nodes)

                        if target_type and not self._is_primitive_type(target_type):
                            callee_id = self._get_component_id(target_type)
                            self.call_relationships.append(CallRelationship(
                                caller=caller_id,
                                callee=callee_id,
                                call_line=node.start_point[0]+1,
                                is_resolved=False
                            ))
                    elif method_node and not object_node:
                        callee_name = method_node.text.decode()
                        self.call_relationships.append(CallRelationship(
                            caller=caller_id,
                            callee=callee_name,
                            call_line=node.start_point[0]+1,
                            is_resolved=False
                        ))

        for child in node.children:
            self._extract_relationships(child, top_level_nodes)

    def _is_primitive_type(self, type_name: str) -> bool:
        """Check if type is a Kotlin primitive or common built-in type."""
        primitives = {
            "Boolean", "Byte", "Char", "Double", "Float", "Int", "Long", "Short",
            "String", "Unit", "Nothing", "Any",
            "List", "Set", "Map", "Collection", "Iterable", "Sequence",
            "MutableList", "MutableSet", "MutableMap", "MutableCollection",
            "Array", "IntArray", "LongArray", "FloatArray", "DoubleArray",
            "BooleanArray", "ByteArray", "CharArray", "ShortArray",
            "Pair", "Triple",
        }
        return type_name in primitives

    def _get_identifier_name(self, node):
        """Get identifier name from a node."""
        name_node = next((c for c in node.children if c.type == "identifier"), None)
        return name_node.text.decode() if name_node else None

    def _get_type_name(self, node) -> Optional[str]:
        """Get the primary type name from a type node, stripping generics."""
        if node.type == "user_type":
            id_node = next((c for c in node.children if c.type == "identifier"), None)
            return id_node.text.decode() if id_node else None
        elif node.type == "nullable_type":
            inner = next((c for c in node.children if c.type == "user_type"), None)
            if inner:
                return self._get_type_name(inner)
        elif node.type == "identifier":
            return node.text.decode()
        return None

    def _get_root_identifier(self, nav_node):
        """Get the root identifier from a chain of navigation_expressions."""
        first_child = nav_node.children[0] if nav_node.children else None
        if first_child:
            if first_child.type == "identifier":
                return first_child
            elif first_child.type == "navigation_expression":
                return self._get_root_identifier(first_child)
        return None

    def _find_containing_class_name(self, node):
        """Walk up to find the containing class/object/interface name."""
        current = node.parent
        while current:
            if current.type in ("class_declaration", "object_declaration"):
                name_node = next((c for c in current.children if c.type == "identifier"), None)
                if name_node:
                    return name_node.text.decode()
            current = current.parent
        return None

    def _find_containing_class(self, node, top_level_nodes):
        """Find the component ID of the containing class."""
        class_name = self._find_containing_class_name(node)
        if class_name and class_name in top_level_nodes:
             return self._get_component_id(class_name)
        return None

    def _find_containing_method(self, node):
        """Find the component ID of the containing function/method."""
        current = node.parent
        while current:
            if current.type == "function_declaration":
                method_name = self._get_identifier_name(current)
                class_name = self._find_containing_class_name(current)
                if method_name:
                    if class_name:
                        return self._get_component_id(f"{class_name}.{method_name}")
                    return self._get_component_id(method_name)
            current = current.parent
        return None

    def _find_variable_type(self, node, variable_name: str, top_level_nodes) -> Optional[str]:
        """
        Try to resolve the type of a variable by searching local declarations,
        function parameters, constructor parameters, and class properties.
        """
        func_node = node.parent
        while func_node and func_node.type != "function_declaration":
            func_node = func_node.parent

        if func_node:
            params_node = next(
                (c for c in func_node.children if c.type == "function_value_parameters"), None
            )
            if params_node:
                for param in params_node.children:
                    if param.type == "parameter":
                        param_name_node = next(
                            (c for c in param.children if c.type == "identifier"), None
                        )
                        if param_name_node and param_name_node.text.decode() == variable_name:
                            type_node = next(
                                (c for c in param.children if c.type in ("user_type", "nullable_type")), None
                            )
                            if type_node:
                                return self._get_type_name(type_node)

            body_node = next(
                (c for c in func_node.children if c.type == "function_body"), None
            )
            if body_node:
                block = next((c for c in body_node.children if c.type == "block"), None)
                if block:
                    result = self._search_variable_declaration(block, variable_name)
                    if result:
                        return result

        class_node = node.parent
        while class_node and class_node.type not in ("class_declaration", "object_declaration"):
            class_node = class_node.parent

        if class_node:
            primary_ctor = next(
                (c for c in class_node.children if c.type == "primary_constructor"), None
            )
            if primary_ctor:
                class_params = next(
                    (c for c in primary_ctor.children if c.type == "class_parameters"), None
                )
                if class_params:
                    for param in class_params.children:
                        if param.type == "class_parameter":
                            param_name = next(
                                (c for c in param.children if c.type == "identifier"), None
                            )
                            if param_name and param_name.text.decode() == variable_name:
                                type_node = next(
                                    (c for c in param.children if c.type in ("user_type", "nullable_type")), None
                                )
                                if type_node:
                                    return self._get_type_name(type_node)

            class_body = next(
                (c for c in class_node.children if c.type in ("class_body", "enum_class_body")), None
            )
            if class_body:
                for body_child in class_body.children:
                    if body_child.type == "property_declaration":
                        var_decl = next(
                            (c for c in body_child.children if c.type == "variable_declaration"), None
                        )
                        if var_decl:
                            prop_name = next(
                                (c for c in var_decl.children if c.type == "identifier"), None
                            )
                            if prop_name and prop_name.text.decode() == variable_name:
                                type_node = next(
                                    (c for c in var_decl.children if c.type in ("user_type", "nullable_type")), None
                                )
                                if type_node:
                                    return self._get_type_name(type_node)

        return None

    def _search_variable_declaration(self, block_node, variable_name: str) -> Optional[str]:
        """Search for a local variable declaration with explicit type annotation in a block."""
        for child in block_node.children:
            if child.type == "property_declaration":
                var_decl = next(
                    (c for c in child.children if c.type == "variable_declaration"), None
                )
                if var_decl:
                    name_node = next(
                        (c for c in var_decl.children if c.type == "identifier"), None
                    )
                    if name_node and name_node.text.decode() == variable_name:
                        type_node = next(
                            (c for c in var_decl.children if c.type in ("user_type", "nullable_type")), None
                        )
                        if type_node:
                            return self._get_type_name(type_node)

                        init_expr = next(
                            (c for c in child.children if c.type == "call_expression"), None
                        )
                        if init_expr:
                            call_id = next(
                                (c for c in init_expr.children if c.type == "identifier"), None
                            )
                            if call_id:
                                inferred = call_id.text.decode()
                                if inferred and inferred[0].isupper():
                                    return inferred

            elif child.type == "block":
                result = self._search_variable_declaration(child, variable_name)
                if result:
                    return result

        return None

def analyze_kotlin_file(file_path: str, content: str, repo_path: Optional[str] = None) -> Tuple[List[Node], List[CallRelationship]]:
    analyzer = TreeSitterKotlinAnalyzer(file_path, content, repo_path)
    return analyzer.nodes, analyzer.call_relationships

class NamespaceResolver:
    """Resolves PHP class names to fully qualified names using use statements."""

    def __init__(self):
        self.current_namespace: str = ""
        self.use_map: Dict[str, str] = {}  # alias -> fully_qualified_name

    def register_namespace(self, ns: str):
        """Set the current namespace."""
        self.current_namespace = ns.replace("\\\\", "\\")

    def register_use(self, fqn: str, alias: str = None):
        """Register a use statement with optional alias."""
        fqn = fqn.replace("\\\\", "\\").lstrip("\\")
        alias = alias or fqn.split("\\")[-1]
        self.use_map[alias] = fqn

    def resolve(self, name: str) -> str:
        """Resolve a name to its fully qualified form."""
        if not name:
            return name

        name = name.replace("\\\\", "\\")

        # Already fully qualified
        if name.startswith("\\"):
            return name[1:]

        # Check use map for alias
        if name in self.use_map:
            return self.use_map[name]

        # Check if first part is an alias (for partial qualified names)
        parts = name.split("\\")
        if parts[0] in self.use_map:
            base = self.use_map[parts[0]]
            if len(parts) > 1:
                return f"{base}\\{'\\'.join(parts[1:])}"
            return base

        # Prepend current namespace
        if self.current_namespace:
            return f"{self.current_namespace}\\{name}"

        return name

class TreeSitterPHPAnalyzer:
    """Analyzes PHP files using tree-sitter to extract nodes and relationships."""

    def __init__(self, file_path: str, content: str, repo_path: str = None):
        self.file_path = Path(file_path)
        self.content = content
        self.repo_path = repo_path or ""
        self.nodes: List[Node] = []
        self.call_relationships: List[CallRelationship] = []
        self.namespace_resolver = NamespaceResolver()
        self._top_level_nodes: Dict[str, Node] = {}

        # Check if this is a template file that should be skipped
        if self._is_template_file():
            logger.debug(f"Skipping template file: {file_path}")
            return

        self._analyze()

    def _is_template_file(self) -> bool:
        """Check if file is a PHP template that should be skipped."""
        file_str = str(self.file_path)

        # Check extension patterns
        for pattern in TEMPLATE_PATTERNS:
            if file_str.endswith(pattern):
                return True

        # Check directory patterns
        for dir_pattern in TEMPLATE_DIRECTORIES:
            if f"/{dir_pattern}/" in file_str or f"\\{dir_pattern}\\" in file_str:
                return True

        return False

    def _get_module_path(self) -> str:
        """Get module path for the file."""
        if self.repo_path:
            try:
                rel_path = os.path.relpath(str(self.file_path), self.repo_path)
            except ValueError:
                rel_path = str(self.file_path)
        else:
            rel_path = str(self.file_path)

        # Remove .php extension
        for ext in ['.php', '.phtml', '.inc']:
            if rel_path.endswith(ext):
                rel_path = rel_path[:-len(ext)]
                break

        return rel_path.replace('/', '.').replace('\\', '.')

    def _get_relative_path(self) -> str:
        """Get relative path from repo root."""
        if self.repo_path:
            try:
                return os.path.relpath(str(self.file_path), self.repo_path)
            except ValueError:
                return str(self.file_path)
        return str(self.file_path)

    def _get_component_id(self, name: str, parent_class: str = None) -> str:
        """Generate component ID for a node."""
        rel_path = self._get_relative_path()
        if parent_class:
            return f"{rel_path}::{parent_class}.{name}"
        return f"{rel_path}::{name}"

    def _analyze(self):
        """Parse and analyze the PHP file."""
        try:
            # Use language_php for mixed PHP/HTML files (most common)
            php_lang_capsule = tree_sitter_php.language_php()
            php_language = Language(php_lang_capsule)
            parser = Parser(php_language)

            tree = parser.parse(bytes(self.content, "utf8"))
            root = tree.root_node
            lines = self.content.splitlines()

            # First pass: extract namespace and use statements
            self._extract_namespace_info(root)

            # Second pass: extract nodes
            self._extract_nodes(root, lines, depth=0)

            # Third pass: extract relationships
            self._extract_relationships(root, depth=0)

        except RecursionError:
            logger.warning(f"Max recursion depth exceeded in {self.file_path}")
        except Exception as e:
            logger.error(f"Error parsing PHP file {self.file_path}: {e}")

    def _extract_namespace_info(self, node, depth: int = 0):
        """Extract namespace and use statements from the AST."""
        if depth > MAX_RECURSION_DEPTH:
            return

        if node.type == "namespace_definition":
            # Get namespace name
            name_node = self._find_child_by_type(node, "namespace_name")
            if name_node:
                self.namespace_resolver.register_namespace(name_node.text.decode())

        elif node.type == "namespace_use_declaration":
            self._extract_use_statement(node)

        for child in node.children:
            self._extract_namespace_info(child, depth + 1)

    def _extract_use_statement(self, node):
        """Extract use statement(s) from a namespace_use_declaration node."""
        # Handle group use: use App\{User, Post};
        group_node = self._find_child_by_type(node, "namespace_use_group")
        if group_node:
            prefix_node = self._find_child_by_type(node, "namespace_name")
            prefix = prefix_node.text.decode() if prefix_node else ""

            for child in group_node.children:
                if child.type == "namespace_use_group_clause":
                    name_node = self._find_child_by_type(child, "namespace_name")
                    alias_node = self._find_child_by_type(child, "namespace_aliasing_clause")

                    if name_node:
                        fqn = f"{prefix}\\{name_node.text.decode()}" if prefix else name_node.text.decode()
                        alias = None
                        if alias_node:
                            alias_name = self._find_child_by_type(alias_node, "name")
                            if alias_name:
                                alias = alias_name.text.decode()
                        self.namespace_resolver.register_use(fqn, alias)
        else:
            # Handle simple use: use App\User; or use App\User as U;
            for child in node.children:
                if child.type == "namespace_use_clause":
                    name_node = self._find_child_by_type(child, "qualified_name") or \
                                self._find_child_by_type(child, "namespace_name")
                    alias_node = self._find_child_by_type(child, "namespace_aliasing_clause")

                    if name_node:
                        fqn = name_node.text.decode()
                        alias = None
                        if alias_node:
                            alias_name = self._find_child_by_type(alias_node, "name")
                            if alias_name:
                                alias = alias_name.text.decode()
                        self.namespace_resolver.register_use(fqn, alias)

    def _extract_nodes(self, node, lines: List[str], depth: int = 0, parent_class: str = None):
        """Extract class, interface, trait, enum, function, and method nodes."""
        if depth > MAX_RECURSION_DEPTH:
            logger.warning(f"Max recursion depth reached in {self.file_path}")
            return

        node_type = None
        node_name = None
        docstring = ""

        # Get preceding docstring (PHPDoc)
        docstring = self._get_preceding_docstring(node, lines)

        if node.type == "class_declaration":
            # Check for abstract class
            is_abstract = any(
                c.type == "abstract_modifier" or
                (c.type == "modifier" and c.text.decode() == "abstract")
                for c in node.children
            )
            node_type = "abstract class" if is_abstract else "class"
            name_node = self._find_child_by_type(node, "name")
            node_name = name_node.text.decode() if name_node else None

        elif node.type == "interface_declaration":
            node_type = "interface"
            name_node = self._find_child_by_type(node, "name")
            node_name = name_node.text.decode() if name_node else None

        elif node.type == "trait_declaration":
            node_type = "trait"
            name_node = self._find_child_by_type(node, "name")
            node_name = name_node.text.decode() if name_node else None

        elif node.type == "enum_declaration":
            node_type = "enum"
            name_node = self._find_child_by_type(node, "name")
            node_name = name_node.text.decode() if name_node else None

        elif node.type == "function_definition":
            node_type = "function"
            name_node = self._find_child_by_type(node, "name")
            node_name = name_node.text.decode() if name_node else None

        elif node.type == "method_declaration":
            node_type = "method"
            name_node = self._find_child_by_type(node, "name")
            if name_node:
                method_name = name_node.text.decode()
                containing_class = parent_class or self._find_containing_class_name(node)
                if containing_class:
                    node_name = f"{containing_class}.{method_name}"
                else:
                    node_name = method_name

        if node_type and node_name:
            component_id = self._get_component_id(node_name)
            relative_path = self._get_relative_path()

            # Extract parameters for functions/methods
            parameters = None
            if node_type in ("function", "method"):
                parameters = self._extract_parameters(node)

            # Extract base classes for classes
            base_classes = None
            if node_type in ("class", "abstract class"):
                base_classes = self._extract_base_classes(node)

            node_obj = Node(
                id=component_id,
                name=node_name,
                component_type=node_type,
                file_path=str(self.file_path),
                relative_path=relative_path,
                source_code="\n".join(lines[node.start_point[0]:node.end_point[0]+1]),
                start_line=node.start_point[0] + 1,
                end_line=node.end_point[0] + 1,
                has_docstring=bool(docstring),
                docstring=docstring,
                parameters=parameters,
                node_type=node_type,
                base_classes=base_classes,
                class_name=parent_class,
                display_name=f"{node_type} {node_name}",
                component_id=component_id
            )
            self.nodes.append(node_obj)
            self._top_level_nodes[node_name] = node_obj

            # Track current class for method extraction
            if node_type in ("class", "abstract class", "interface", "trait", "enum"):
                parent_class = node_name

        # Recursively process children
        for child in node.children:
            self._extract_nodes(child, lines, depth + 1, parent_class)

    def _extract_relationships(self, node, depth: int = 0):
        """Extract dependency relationships from the AST."""
        if depth > MAX_RECURSION_DEPTH:
            return

        # 1. Use statements (already registered, now create relationships)
        if node.type == "namespace_use_declaration":
            self._add_use_relationships(node)

        # 2. Class inheritance (extends)
        if node.type == "class_declaration":
            class_name = self._get_name_from_node(node)
            base_clause = self._find_child_by_type(node, "base_clause")
            if base_clause and class_name:
                base_name = self._get_type_from_clause(base_clause)
                if base_name and not self._is_primitive(base_name):
                    resolved_base = self.namespace_resolver.resolve(base_name)
                    self.call_relationships.append(CallRelationship(
                        caller=self._get_component_id(class_name),
                        callee=resolved_base.replace("\\", "."),
                        call_line=node.start_point[0] + 1,
                        is_resolved=False
                    ))

        # 3. Interface implementation (implements)
        if node.type in ("class_declaration", "enum_declaration"):
            implementer_name = self._get_name_from_node(node)
            interface_clause = self._find_child_by_type(node, "class_interface_clause")
            if interface_clause and implementer_name:
                for child in interface_clause.children:
                    if child.type in ("name", "qualified_name"):
                        interface_name = child.text.decode()
                        if not self._is_primitive(interface_name):
                            resolved_interface = self.namespace_resolver.resolve(interface_name)
                            self.call_relationships.append(CallRelationship(
                                caller=self._get_component_id(implementer_name),
                                callee=resolved_interface.replace("\\", "."),
                                call_line=node.start_point[0] + 1,
                                is_resolved=False
                            ))

        # 4. Object creation (new)
        if node.type == "object_creation_expression":
            containing_class = self._find_containing_class_name(node)
            type_node = self._find_child_by_type(node, "name") or \
                       self._find_child_by_type(node, "qualified_name")
            if type_node:
                created_type = type_node.text.decode()
                if not self._is_primitive(created_type) and containing_class:
                    resolved_type = self.namespace_resolver.resolve(created_type)
                    self.call_relationships.append(CallRelationship(
                        caller=self._get_component_id(containing_class),
                        callee=resolved_type.replace("\\", "."),
                        call_line=node.start_point[0] + 1,
                        is_resolved=False
                    ))

        # 5. Static method calls (::)
        if node.type == "scoped_call_expression":
            containing_class = self._find_containing_class_name(node)
            scope_node = self._find_child_by_type(node, "name") or \
                        self._find_child_by_type(node, "qualified_name")
            if scope_node and containing_class:
                target_class = scope_node.text.decode()
                if not self._is_primitive(target_class):
                    resolved_target = self.namespace_resolver.resolve(target_class)
                    self.call_relationships.append(CallRelationship(
                        caller=self._get_component_id(containing_class),
                        callee=resolved_target.replace("\\", "."),
                        call_line=node.start_point[0] + 1,
                        is_resolved=False
                    ))

        # 6. Property promotion in constructor (PHP 8+)
        if node.type == "property_promotion_parameter":
            containing_class = self._find_containing_class_name(node)
            type_node = self._find_child_by_type(node, "type_list") or \
                       self._find_child_by_type(node, "named_type")
            if type_node and containing_class:
                type_name = self._extract_type_name(type_node)
                if type_name and not self._is_primitive(type_name):
                    resolved_type = self.namespace_resolver.resolve(type_name)
                    self.call_relationships.append(CallRelationship(
                        caller=self._get_component_id(containing_class),
                        callee=resolved_type.replace("\\", "."),
                        call_line=node.start_point[0] + 1,
                        is_resolved=False
                    ))

        # Recursively process children
        for child in node.children:
            self._extract_relationships(child, depth + 1)

    def _add_use_relationships(self, node):
        """Add relationships for use statements."""
        # Get all use clauses from the declaration
        for child in node.children:
            if child.type == "namespace_use_clause":
                name_node = self._find_child_by_type(child, "qualified_name") or \
                           self._find_child_by_type(child, "namespace_name")
                if name_node:
                    fqn = name_node.text.decode().replace("\\", ".")
                    # Add relationship from file to imported class
                    file_id = self._get_relative_path()
                    self.call_relationships.append(CallRelationship(
                        caller=file_id,
                        callee=fqn,
                        call_line=node.start_point[0] + 1,
                        is_resolved=False
                    ))
            elif child.type == "namespace_use_group":
                prefix_node = self._find_child_by_type(node, "namespace_name")
                prefix = prefix_node.text.decode() if prefix_node else ""

                for group_child in child.children:
                    if group_child.type == "namespace_use_group_clause":
                        name_node = self._find_child_by_type(group_child, "namespace_name")
                        if name_node:
                            fqn = f"{prefix}\\{name_node.text.decode()}" if prefix else name_node.text.decode()
                            file_id = self._get_relative_path()
                            self.call_relationships.append(CallRelationship(
                                caller=file_id,
                                callee=fqn.replace("\\", "."),
                                call_line=node.start_point[0] + 1,
                                is_resolved=False
                            ))

    def _find_child_by_type(self, node, child_type: str):
        """Find first child of a specific type."""
        for child in node.children:
            if child.type == child_type:
                return child
        return None

    def _get_name_from_node(self, node) -> Optional[str]:
        """Get name from a declaration node."""
        name_node = self._find_child_by_type(node, "name")
        return name_node.text.decode() if name_node else None

    def _get_type_from_clause(self, clause_node) -> Optional[str]:
        """Extract type name from a base_clause or interface_clause."""
        for child in clause_node.children:
            if child.type in ("name", "qualified_name"):
                return child.text.decode()
        return None

    def _extract_type_name(self, type_node) -> Optional[str]:
        """Extract type name from a type node."""
        if type_node.type == "named_type":
            name_node = self._find_child_by_type(type_node, "name") or \
                       self._find_child_by_type(type_node, "qualified_name")
            if name_node:
                return name_node.text.decode()
        elif type_node.type in ("name", "qualified_name"):
            return type_node.text.decode()
        elif type_node.type == "type_list":
            # Get first type from union/intersection
            for child in type_node.children:
                if child.type == "named_type":
                    return self._extract_type_name(child)
        return type_node.text.decode() if hasattr(type_node, 'text') else None

    def _find_containing_class_name(self, node) -> Optional[str]:
        """Find the name of the containing class/interface/trait/enum."""
        current = node.parent
        while current:
            if current.type in ("class_declaration", "interface_declaration",
                               "trait_declaration", "enum_declaration"):
                name_node = self._find_child_by_type(current, "name")
                if name_node:
                    return name_node.text.decode()
            current = current.parent
        return None

    def _get_preceding_docstring(self, node, lines: List[str]) -> str:
        """Extract PHPDoc comment preceding a node."""
        if node.start_point[0] == 0:
            return ""

        # Look at previous sibling or check lines before
        prev_sibling = node.prev_named_sibling
        if prev_sibling and prev_sibling.type == "comment":
            comment_text = prev_sibling.text.decode()
            if comment_text.startswith("/**"):
                return comment_text

        # Check lines directly before the node
        start_line = node.start_point[0]
        if start_line > 0:
            for i in range(start_line - 1, max(0, start_line - 10), -1):
                line = lines[i].strip() if i < len(lines) else ""
                if line.endswith("*/"):
                    # Found end of docblock, now find start
                    docblock_lines = []
                    for j in range(i, max(0, i - 50), -1):
                        docblock_lines.insert(0, lines[j] if j < len(lines) else "")
                        if "/**" in (lines[j] if j < len(lines) else ""):
                            return "\n".join(docblock_lines)
                elif line and not line.startswith("*") and not line.startswith("/**"):
                    break

        return ""

    def _extract_parameters(self, node) -> Optional[List[str]]:
        """Extract function/method parameters as list of strings."""
        params_node = self._find_child_by_type(node, "formal_parameters")
        if params_node:
            params = []
            for child in params_node.children:
                if child.type in ("simple_parameter", "property_promotion_parameter", "variadic_parameter"):
                    # Get the variable name
                    var_node = self._find_child_by_type(child, "variable_name")
                    if var_node:
                        param_text = var_node.text.decode()
                        # Get type if present
                        type_node = self._find_child_by_type(child, "named_type") or \
                                   self._find_child_by_type(child, "primitive_type")
                        if type_node:
                            param_text = f"{type_node.text.decode()} {param_text}"
                        params.append(param_text)
            return params if params else None
        return None

    def _extract_base_classes(self, node) -> Optional[List[str]]:
        """Extract base class names from a class declaration."""
        base_classes = []

        base_clause = self._find_child_by_type(node, "base_clause")
        if base_clause:
            for child in base_clause.children:
                if child.type in ("name", "qualified_name"):
                    base_classes.append(child.text.decode())

        interface_clause = self._find_child_by_type(node, "class_interface_clause")
        if interface_clause:
            for child in interface_clause.children:
                if child.type in ("name", "qualified_name"):
                    base_classes.append(child.text.decode())

        return base_classes if base_classes else None

    def _is_primitive(self, type_name: str) -> bool:
        """Check if type is a PHP primitive or built-in type."""
        if not type_name:
            return True
        # Remove leading backslash and check
        clean_name = type_name.lstrip("\\").split("\\")[-1]
        return clean_name.lower() in {p.lower() for p in PHP_PRIMITIVES}

class PythonASTAnalyzer(ast.NodeVisitor):

    def __init__(self, file_path: str, content: str, repo_path: Optional[str] = None):
        """
        Initialize the Python AST analyzer.

        Args:
            file_path: Path to the Python file being analyzed
            content: Raw content of the Python file
            repo_path: Repository root path for calculating relative paths
        """
        self.file_path = file_path
        self.repo_path = repo_path
        self.content = content
        self.lines = content.splitlines()
        self.nodes: List[Node] = []
        self.call_relationships: List[CallRelationship] = []
        self.current_class_name: str | None = None
        self.current_function_name: str | None = None

        self.top_level_nodes = {}

    def _get_relative_path(self) -> str:
        """Get relative path from repo root."""
        if self.repo_path:
            return os.path.relpath(self.file_path, self.repo_path)
        return str(self.file_path)

    def _get_module_path(self) -> str:
        try:
            relative_path = self._get_relative_path()
            path = relative_path
            for ext in ['.py', '.pyx']:
                if path.endswith(ext):
                    path = path[:-len(ext)]
                    break
            return path.replace('/', '.').replace('\\', '.')
        except:
            return str(self.file_path).replace('/', '.').replace('\\', '.')

    def _get_component_id(self, name: str) -> str:
        """Generate component ID in relative_path::name format."""
        rel_path = self._get_relative_path()
        if self.current_class_name:
            return f"{rel_path}::{self.current_class_name}.{name}"
        else:
            return f"{rel_path}::{name}"

    def generic_visit(self, node):
        """Override generic_visit to continue AST traversal."""
        super().generic_visit(node)

    def visit_ClassDef(self, node: ast.ClassDef):
        """Visit class definition and add to top-level nodes."""

        base_classes = [self._extract_base_class_name(base) for base in node.bases]
        base_classes = [name for name in base_classes if name is not None]

        component_id = f"{self._get_relative_path()}::{node.name}"
        relative_path = self._get_relative_path()

        class_node = Node(
            id=component_id,
            name=node.name,
            component_type="class",
            file_path=str(self.file_path),
            relative_path=relative_path,
            source_code="\n".join(self.lines[node.lineno - 1 : node.end_lineno or node.lineno]),
            start_line=node.lineno,
            end_line=node.end_lineno,
            has_docstring=bool(ast.get_docstring(node)),
            docstring=ast.get_docstring(node) or "",
            parameters=None,
            node_type="class",
            base_classes=base_classes if base_classes else None,
            class_name=None,
            display_name=f"class {node.name}",
            component_id=component_id
        )
        self.nodes.append(class_node)
        self.top_level_nodes[node.name] = class_node

        for base_name in base_classes:
            if base_name in self.top_level_nodes:
                self.call_relationships.append(CallRelationship(
                    caller=component_id,
                    callee=f"{self._get_relative_path()}::{base_name}",
                    call_line=node.lineno,
                    is_resolved=True
                ))

        self.current_class_name = node.name
        self.generic_visit(node)
        self.current_class_name = None

    def _extract_base_class_name(self, base):
        """Extract base class name from AST node."""
        if isinstance(base, ast.Name):
            return base.id
        elif isinstance(base, ast.Attribute):
            parts = []
            node = base
            while isinstance(node, ast.Attribute):
                parts.append(node.attr)
                node = node.value
            if isinstance(node, ast.Name):
                parts.append(node.id)
            return ".".join(reversed(parts))
        return None

    def _process_function_node(self, node: ast.FunctionDef | ast.AsyncFunctionDef):
        """Process function definition - only add to nodes if it's top-level."""

        if not self.current_class_name:
            component_id = f"{self._get_relative_path()}::{node.name}"
            relative_path = self._get_relative_path()

            func_node = Node(
                id=component_id,
                name=node.name,
                component_type="function",
                file_path=str(self.file_path),
                relative_path=relative_path,
                source_code="\n".join(self.lines[node.lineno - 1 : node.end_lineno or node.lineno]),
                start_line=node.lineno,
                end_line=node.end_lineno,
                has_docstring=bool(ast.get_docstring(node)),
                docstring=ast.get_docstring(node) or "",
                parameters=[arg.arg for arg in node.args.args],
                node_type="function",
                base_classes=None,
                class_name=None,
                display_name=f"function {node.name}",
                component_id=component_id
            )
            if self._should_include_function(func_node):
                self.nodes.append(func_node)
                self.top_level_nodes[node.name] = func_node

        self.current_function_name = node.name
        self.generic_visit(node)
        self.current_function_name = None

    def _should_include_function(self, func: Node) -> bool:
        if func.name.startswith("_test_"):
            return False
        return True

    def visit_FunctionDef(self, node: ast.FunctionDef):
        """Visit function definition and extract function information."""
        self._process_function_node(node)

    def visit_AsyncFunctionDef(self, node: ast.AsyncFunctionDef):
        """Visit async function definition and extract function information."""
        self._process_function_node(node)

    def visit_Call(self, node: ast.Call):
        """Visit function call nodes and record relationships between top-level nodes."""

        if self.current_class_name or (self.current_function_name and not self.current_class_name):
            call_name = self._get_call_name(node.func)
            if call_name:
                if self.current_class_name:
                    caller_id = f"{self._get_relative_path()}::{self.current_class_name}"
                else:
                    caller_id = f"{self._get_relative_path()}::{self.current_function_name}"

                if call_name in self.top_level_nodes:
                    callee_id = f"{self._get_relative_path()}::{call_name}"
                else:
                    callee_id = call_name

                relationship = CallRelationship(
                    caller=caller_id,
                    callee=callee_id,
                    call_line=node.lineno,
                    is_resolved=call_name in self.top_level_nodes  
                )
                self.call_relationships.append(relationship)

        self.generic_visit(node)

    def _get_call_name(self, node) -> str | None:
        """
        Extract function name from a call node.
        Handles simple names, attributes (obj.method), and filters built-ins.
        """
        PYTHON_BUILTINS = {
            "print", "len", "str", "int", "float", "bool", "list", "dict", "tuple", "set",
            "range", "enumerate", "zip", "isinstance", "hasattr", "getattr", "setattr",
            "open", "super", "__import__", "type", "object", "Exception", "ValueError",
            "TypeError", "KeyError", "IndexError", "AttributeError", "ImportError",
            "max", "min", "sum", "abs", "round", "sorted", "reversed", "filter", "map",
            "any", "all", "next", "iter", "callable", "repr", "format", "exec", "eval"
        }

        if isinstance(node, ast.Name):
            if node.id in PYTHON_BUILTINS:
                return None
            return node.id
        elif isinstance(node, ast.Attribute):
            if isinstance(node.value, ast.Name):
                if node.value.id in PYTHON_BUILTINS:
                    return None
                return f"{node.value.id}.{node.attr}"
            elif isinstance(node.value, ast.Attribute):
                base_name = self._get_call_name(node.value)
                if base_name:
                    return f"{base_name}.{node.attr}"
            return node.attr
        return None

    def analyze(self):
        """Analyze the Python file and extract functions and relationships."""

        try:
            # Suppress SyntaxWarnings about invalid escape sequences in source code
            # These warnings come from regex patterns like '\(' or '\.' in the analyzed files
            with warnings.catch_warnings():
                warnings.filterwarnings("ignore", category=SyntaxWarning)
                tree = ast.parse(self.content)
            self.visit(tree)

            logger.debug(
                f"Python analysis complete for {self.file_path}: {len(self.nodes)} nodes, "
                f"{len(self.call_relationships)} relationships"
            )
        except SyntaxError as e:
            logger.warning(f"Could not parse {self.file_path}: {e}")
        except Exception as e:
            logger.error(f"Error analyzing {self.file_path}: {e}", exc_info=True)

class TreeSitterTSAnalyzer:

    def __init__(self, file_path: str, content: str, repo_path: str = None):
        self.file_path = Path(file_path)
        self.content = content
        self.repo_path = repo_path or ""
        self.nodes: List[Node] = []
        self.call_relationships: List[CallRelationship] = []

        self.top_level_nodes = {}

        try:
            language_capsule = tree_sitter_typescript.language_typescript()
            self.ts_language = Language(language_capsule)
            self.parser = Parser(self.ts_language)

        except Exception as e:
            logger.error(f"Failed to initialize TypeScript parser: {e}")
            logger.error(f"Traceback: {traceback.format_exc()}")
            self.parser = None
            self.ts_language = None

    def analyze(self) -> None:
        if self.parser is None:
            logger.debug(f"Skipping {self.file_path} - parser initialization failed")
            return

        try:
            tree = self.parser.parse(bytes(self.content, "utf8"))
            root_node = tree.root_node

            logger.debug(f"Parsed AST with root node type: {root_node.type}")

            all_entities = {}  
            self._extract_all_entities(root_node, all_entities)

            self._filter_top_level_declarations(all_entities)

            self._extract_all_relationships(root_node, all_entities)

        except Exception as e:
            logger.error(f"Error analyzing TypeScript file {self.file_path}: {e}", exc_info=True)

    def _extract_all_entities(self, node, all_entities: dict, depth=0) -> None:
        entity = None
        entity_name = None

        if node.type == "function_declaration":
            entity = self._extract_function_entity(node, "function", depth)
        elif node.type == "generator_function_declaration":
            entity = self._extract_function_entity(node, "generator_function", depth)
        elif node.type == "arrow_function":
            entity = self._extract_arrow_function_entity(node, depth)
        elif node.type == "method_definition":
            entity = self._extract_method_entity(node, depth)
        elif node.type == "class_declaration":
            entity = self._extract_class_entity(node, "class", depth)
        elif node.type == "abstract_class_declaration":
            entity = self._extract_class_entity(node, "abstract_class", depth)
        elif node.type == "interface_declaration":
            entity = self._extract_interface_entity(node, depth)
        elif node.type == "type_alias_declaration":
            entity = self._extract_type_alias_entity(node, depth)
        elif node.type == "enum_declaration":
            entity = self._extract_enum_entity(node, depth)
        elif node.type == "variable_declarator":
            entity = self._extract_variable_entity(node, depth)
        elif node.type == "export_statement":
            entity = self._extract_export_statement_entity(node, depth)
        elif node.type == "lexical_declaration":
            entity = self._extract_lexical_declaration_entity(node, depth)
        elif node.type == "variable_declaration":
            entity = self._extract_variable_declaration_entity(node, depth)
        elif node.type == "ambient_declaration":
            entity = self._extract_ambient_declaration_entity(node, depth)

        if entity and entity.get('name'):
            entity_name = entity['name']
            entity['depth'] = depth  
            entity['node'] = node   
            entity['parent_context'] = self._get_parent_context(node)  
            all_entities[entity_name] = entity

        for child in node.children:
            self._extract_all_entities(child, all_entities, depth + 1)

    def _filter_top_level_declarations(self, all_entities: dict) -> None:
        for entity_name, entity_data in all_entities.items():
            if self._is_actually_top_level(entity_data):
                node_obj = self._create_node_from_entity(entity_data)
                if node_obj and self._should_include_node(node_obj):
                    self.nodes.append(node_obj)
                    self.top_level_nodes[entity_name] = node_obj

                    if entity_data["type"] in ["class_declaration", "abstract_class_declaration"]:
                        self._extract_constructor_dependencies(entity_data["node"], entity_name)

    def _is_actually_top_level(self, entity_data: dict) -> bool:
        node = entity_data.get('node')
        if not node or not node.parent:
            return True

        entity_type = entity_data.get('type')
        if self._is_inside_function_body(node):
            return False

        current = node.parent
        while current:
            parent_type = current.type

            if parent_type == "program":
                return True

            if parent_type == "export_statement":
                return True

            if parent_type == "ambient_declaration":
                return True

            if parent_type == "module":
                return True

            if parent_type == "statement_block":
                grandparent = current.parent
                if grandparent and grandparent.type in ["module", "ambient_declaration"]:
                    return True

            current = current.parent

        return False

    def _is_inside_function_body(self, node) -> bool:
        current = node.parent
        while current:
            if current.type == "statement_block":
                if current.parent and current.parent.type in [
                    "function_declaration", "generator_function_declaration", 
                    "arrow_function", "function_expression", "method_definition"
                ]:
                    return True
            current = current.parent
        return False

    def _extract_ambient_declaration_entity(self, node, depth: int) -> dict:
        name = ""
        for child in node.children:
            if child.type == "module":
                for grandchild in child.children:
                    if grandchild.type == "string":
                        name = self._get_node_text(grandchild).strip("'\"")
                        break
                break
            elif child.type == "namespace":
                name = self._get_node_text(child.children[1]) if len(child.children) > 1 else "unknown_namespace"
                break

        return {
            'name': f"{name}",
            'type': 'ambient_declaration',
            'start_line': node.start_point[0] + 1,
            'end_line': node.end_point[0] + 1,
            'parameters': [],
            'return_type': None,
            'modifiers': ['ambient'],
            'complexity': 1
        }

    def _get_parent_context(self, node) -> str:
        """Get the parent context of a node for better top-level detection"""
        if not node.parent:
            return "root"

        parent_type = node.parent.type
        if parent_type in ["program", "source_file"]:
            return "program"
        elif parent_type == "export_statement":
            return "export"
        elif parent_type == "ambient_declaration":
            return "ambient"
        elif parent_type == "module":
            return "module"
        elif parent_type == "statement_block":
            if node.parent.parent and node.parent.parent.type in ["module", "ambient_declaration"]:
                return "module_block"
            return "statement_block"
    def _extract_function_entity(self, node, func_type: str, depth: int) -> dict:
        name_node = self._find_child_by_type(node, "identifier")
        if not name_node:
            return None

        func_name = self._get_node_text(name_node)
        parameters = self._extract_parameters(node)
        code_snippet = self._get_node_text(node)

        is_async = "async" in code_snippet.split("function")[0] if "function" in code_snippet else False
        display_name = f"{'async ' if is_async else ''}{func_type} {func_name}"

        return {
            'name': func_name,
            'type': 'function',
            'subtype': func_type,
            'parameters': parameters,
            'code_snippet': code_snippet,
            'display_name': display_name,
            'start_line': node.start_point[0] + 1,
            'end_line': node.end_point[0] + 1,
            'is_async': is_async
        }

    def _extract_arrow_function_entity(self, node, depth: int) -> dict:
        """Extract arrow function"""
        parent = node.parent
        if parent and parent.type == "variable_declarator":
            name_node = self._find_child_by_type(parent, "identifier")
            if name_node:
                func_name = self._get_node_text(name_node)
                parameters = self._extract_parameters(node)
                code_snippet = self._get_node_text(parent)

                is_async = "async" in code_snippet.split("=")[0] if "=" in code_snippet else False
                display_name = f"{'async ' if is_async else ''}arrow function {func_name}"

                return {
                    'name': func_name,
                    'type': 'function',
                    'subtype': 'arrow_function',
                    'parameters': parameters,
                    'code_snippet': code_snippet,
                    'display_name': display_name,
                    'start_line': node.start_point[0] + 1,
                    'end_line': node.end_point[0] + 1,
                    'is_async': is_async
                }
        return None

    def _extract_method_entity(self, node, depth: int) -> dict:
        """Extract method entity (at any depth)."""
        name_node = self._find_child_by_type(node, "property_identifier")
        if not name_node:
            return None

        method_name = self._get_node_text(name_node)
        parameters = self._extract_parameters(node)
        code_snippet = self._get_node_text(node)

        is_async = "async" in code_snippet
        is_static = "static" in code_snippet

        display_name = f"{'static ' if is_static else ''}{'async ' if is_async else ''}method {method_name}"

        return {
            'name': method_name,
            'type': 'function',
            'subtype': 'method',
            'parameters': parameters,
            'code_snippet': code_snippet,
            'display_name': display_name,
            'start_line': node.start_point[0] + 1,
            'end_line': node.end_point[0] + 1,
            'is_async': is_async,
            'is_static': is_static
        }

    def _extract_class_entity(self, node, class_type: str, depth: int) -> dict:
        name_node = self._find_child_by_type(node, "type_identifier") or self._find_child_by_type(node, "identifier")
        if not name_node:
            return None

        class_name = self._get_node_text(name_node)
        base_classes = self._extract_inheritance(node)
        code_snippet = self._get_node_text(node)

        display_name = f"{class_type} {class_name}"
        if base_classes:
            display_name += f" extends {', '.join(base_classes)}"

        return {
            'name': class_name,
            'type': 'class',
            'subtype': class_type,
            'base_classes': base_classes,
            'code_snippet': code_snippet,
            'display_name': display_name,
            'start_line': node.start_point[0] + 1,
            'end_line': node.end_point[0] + 1
        }

    def _extract_interface_entity(self, node, depth: int) -> dict:
        name_node = self._find_child_by_type(node, "type_identifier")
        if not name_node:
            return None

        interface_name = self._get_node_text(name_node)
        base_classes = self._extract_inheritance(node)
        code_snippet = self._get_node_text(node)

        display_name = f"interface {interface_name}"
        if base_classes:
            display_name += f" extends {', '.join(base_classes)}"

        return {
            'name': interface_name,
            'type': 'interface',
            'subtype': 'interface',
            'base_classes': base_classes,
            'code_snippet': code_snippet,
            'display_name': display_name,
            'start_line': node.start_point[0] + 1,
            'end_line': node.end_point[0] + 1
        }

    def _extract_type_alias_entity(self, node, depth: int) -> dict:
        name_node = self._find_child_by_type(node, "type_identifier")
        if not name_node:
            return None

        type_name = self._get_node_text(name_node)
        code_snippet = self._get_node_text(node)

        return {
            'name': type_name,
            'type': 'type',
            'subtype': 'type_alias',
            'code_snippet': code_snippet,
            'display_name': f"type {type_name}",
            'start_line': node.start_point[0] + 1,
            'end_line': node.end_point[0] + 1
        }

    def _extract_enum_entity(self, node, depth: int) -> dict:
        name_node = self._find_child_by_type(node, "identifier")
        if not name_node:
            return None

        enum_name = self._get_node_text(name_node)
        code_snippet = self._get_node_text(node)

        return {
            'name': enum_name,
            'type': 'enum',
            'subtype': 'enum',
            'code_snippet': code_snippet,
            'display_name': f"enum {enum_name}",
            'start_line': node.start_point[0] + 1,
            'end_line': node.end_point[0] + 1
        }

    def _extract_variable_entity(self, node, depth: int) -> dict:
        name_node = self._find_child_by_type(node, "identifier")
        if not name_node:
            return None

        var_name = self._get_node_text(name_node)
        code_snippet = self._get_node_text(node)

        has_function = self._find_child_by_type(node, "arrow_function") or self._find_child_by_type(node, "function_expression")

        return {
            'name': var_name,
            'type': 'variable',
            'subtype': 'variable',
            'code_snippet': code_snippet,
            'display_name': f"variable {var_name}",
            'start_line': node.start_point[0] + 1,
            'end_line': node.end_point[0] + 1,
            'has_function': bool(has_function)
        }

    def _extract_export_statement_entity(self, node, depth: int) -> dict:
        code_snippet = self._get_node_text(node)

        func_decl = self._find_child_by_type(node, "function_declaration")
        class_decl = self._find_child_by_type(node, "class_declaration")
        interface_decl = self._find_child_by_type(node, "interface_declaration")
        lexical_decl = self._find_child_by_type(node, "lexical_declaration")

        if func_decl:
            name_node = self._find_child_by_type(func_decl, "identifier")
            if name_node:
                func_name = self._get_node_text(name_node)
                return {
                    'name': func_name,  
                    'type': 'function',  
                    'subtype': 'export_function',
                    'code_snippet': code_snippet,
                    'display_name': f"export function {func_name}",
                    'start_line': node.start_point[0] + 1,
                    'end_line': node.end_point[0] + 1,
                    'parameters': self._extract_parameters(func_decl),
                    'is_export': True
                }
        elif class_decl:
            name_node = self._find_child_by_type(class_decl, "type_identifier")
            if name_node:
                class_name = self._get_node_text(name_node)
                return {
                    'name': class_name,  
                    'type': 'class',  
                    'subtype': 'export_class',
                    'code_snippet': code_snippet,
                    'display_name': f"export class {class_name}",
                    'start_line': node.start_point[0] + 1,
                    'end_line': node.end_point[0] + 1,
                    'base_classes': self._extract_inheritance(class_decl),
                    'is_export': True
                }
        elif interface_decl:
            name_node = self._find_child_by_type(interface_decl, "type_identifier")
            if name_node:
                interface_name = self._get_node_text(name_node)
                return {
                    'name': interface_name,  
                    'type': 'interface',  
                    'subtype': 'export_interface',
                    'code_snippet': code_snippet,
                    'display_name': f"export interface {interface_name}",
                    'start_line': node.start_point[0] + 1,
                    'end_line': node.end_point[0] + 1,
                    'base_classes': self._extract_inheritance(interface_decl),
                    'is_export': True
                }
        elif lexical_decl:
            var_declarator = self._find_child_by_type(lexical_decl, "variable_declarator")
            if var_declarator:
                name_node = self._find_child_by_type(var_declarator, "identifier")
                func_expr = self._find_child_by_type(var_declarator, "arrow_function") or self._find_child_by_type(var_declarator, "function_expression")
                if name_node and func_expr:
                    var_name = self._get_node_text(name_node)
                    return {
                        'name': var_name,
                        'type': 'function',
                        'subtype': 'export_arrow_function',
                        'code_snippet': code_snippet,
                        'display_name': f"export const {var_name}",
                        'start_line': node.start_point[0] + 1,
                        'end_line': node.end_point[0] + 1,
                        'parameters': self._extract_parameters(func_expr),
                        'is_export': True
                    }

        default_keyword = None
        call_expr = None
        for child in node.children:
            if child.type == "default":
                default_keyword = child
            elif child.type == "call_expression":
                call_expr = child

        if default_keyword and call_expr:
            callee = call_expr.children[0] if call_expr.children else None
            if callee:
                callee_name = self._get_node_text(callee)
                return {
                    'name': callee_name,
                    'type': 'function',
                    'subtype': 'export_default_call',
                    'code_snippet': code_snippet,
                    'display_name': f"export default {callee_name}(...)",
                    'start_line': node.start_point[0] + 1,
                    'end_line': node.end_point[0] + 1,
                    'parameters': [],
                    'is_export': True
                }

        return None 

    def _extract_lexical_declaration_entity(self, node, depth: int) -> dict:
        """Extract lexical declaration entity (const/let)."""
        # Find the variable declarator
        var_declarator = self._find_child_by_type(node, "variable_declarator")
        if not var_declarator:
            return None

        name_node = self._find_child_by_type(var_declarator, "identifier")
        if not name_node:
            return None

        var_name = self._get_node_text(name_node)
        code_snippet = self._get_node_text(node)

        # Check declaration type (const/let)
        decl_type = "const" if "const" in code_snippet else "let"

        has_function = (self._find_child_by_type(var_declarator, "arrow_function") or 
                       self._find_child_by_type(var_declarator, "function_expression"))

        return {
            'name': var_name,
            'type': 'variable',
            'subtype': f'{decl_type}_declaration',
            'code_snippet': code_snippet,
            'display_name': f"{decl_type} {var_name}",
            'start_line': node.start_point[0] + 1,
            'end_line': node.end_point[0] + 1,
            'has_function': bool(has_function),
            'declaration_type': decl_type
        }

    def _extract_variable_declaration_entity(self, node, depth: int) -> dict:
        var_declarator = self._find_child_by_type(node, "variable_declarator")
        if not var_declarator:
            return None

        name_node = self._find_child_by_type(var_declarator, "identifier")
        if not name_node:
            return None

        var_name = self._get_node_text(name_node)
        code_snippet = self._get_node_text(node)

        has_function = (self._find_child_by_type(var_declarator, "arrow_function") or 
                       self._find_child_by_type(var_declarator, "function_expression"))

        return {
            'name': var_name,
            'type': 'variable',
            'subtype': 'var_declaration',
            'code_snippet': code_snippet,
            'display_name': f"var {var_name}",
            'start_line': node.start_point[0] + 1,
            'end_line': node.end_point[0] + 1,
            'has_function': bool(has_function),
            'declaration_type': 'var'
        }

    def _create_node_from_entity(self, entity_data: dict) -> Optional[Node]:
        """Create Node object from entity data."""
        try:
            component_type = entity_data['type']
            name = entity_data['name']
            node_type = entity_data.get('subtype', entity_data['type'])

            component_id = self._get_component_id(name)
            relative_path = self._get_relative_path()

            return Node(
                id=component_id,
                name=name,
                component_type=component_type,
                file_path=str(self.file_path),
                relative_path=relative_path,
                source_code=entity_data['code_snippet'],
                start_line=entity_data['start_line'],
                end_line=entity_data['end_line'],
                has_docstring=False,
                docstring="",
                parameters=entity_data.get('parameters', []),
                node_type=node_type,
                base_classes=entity_data.get('base_classes'),
                class_name=None,
                display_name=entity_data['display_name'],
                component_id=component_id,
            )
        except Exception as e:
            logger.debug(f"Error creating node from entity: {e}")
            return None

    def _should_include_node(self, node: Node) -> bool:
        excluded_names = {"constructor", "__proto__", "prototype"}

        if node.component_type == "variable":
            return False

        return node.name.lower() not in excluded_names

    def _extract_constructor_dependencies(self, class_node, class_name: str) -> None:
        """Extract dependencies from constructor parameters."""
        try:
            class_body = self._find_child_by_type(class_node, "class_body")
            if not class_body:
                return

            for child in class_body.children:
                if child.type == "method_definition":
                    property_name = self._find_child_by_type(child, "property_identifier")
                    if property_name and self._get_node_text(property_name) == "constructor":
                        # Extract parameter types
                        formal_params = self._find_child_by_type(child, "formal_parameters")
                        if formal_params:
                            self._extract_parameter_dependencies(formal_params, class_name)
                        break
        except Exception as e:
            logger.debug(f"Error extracting constructor dependencies: {e}")

    def _extract_parameter_dependencies(self, formal_params, caller_name: str) -> None:
        try:
            for child in formal_params.children:
                if child.type in ["required_parameter", "optional_parameter"]:
                    type_annotation = self._find_child_by_type(child, "type_annotation")
                    if type_annotation:
                        type_id = self._find_child_by_type(type_annotation, "type_identifier")
                        if type_id:
                            dependency_name = self._get_node_text(type_id)
                            if dependency_name and dependency_name != caller_name:
                                caller_id = f"{self._get_relative_path()}::{caller_name}"
                                callee_id = f"{self._get_relative_path()}::{dependency_name}"

                                relationship = CallRelationship(
                                    caller=caller_id,
                                    callee=callee_id,
                                    call_line=child.start_point[0] + 1,
                                    is_resolved=False
                                )

                                self._add_relationship(relationship)
        except Exception as e:
            logger.debug(f"Error extracting parameter dependencies: {e}")


    def _get_module_path(self) -> str:
        if self.repo_path:
            try:
                rel_path = os.path.relpath(str(self.file_path), self.repo_path)
            except ValueError:
                rel_path = str(self.file_path)
        else:
            rel_path = str(self.file_path)

        for ext in ['.ts', '.tsx', '.js', '.jsx', '.mjs', '.cjs']:
            if rel_path.endswith(ext):
                rel_path = rel_path[:-len(ext)]
                break
        return rel_path.replace('/', '.').replace('\\', '.')

    def _get_relative_path(self) -> str:
        if self.repo_path:
            try:
                return os.path.relpath(str(self.file_path), self.repo_path)
            except ValueError:
                return str(self.file_path)
        else:
            return str(self.file_path)

    def _get_component_id(self, name: str) -> str:
        return f"{self._get_relative_path()}::{name}"

    def _extract_inheritance(self, node) -> List[str]:
        """Extract inheritance/implementation relationships."""
        base_classes = []

        extends_clause = self._find_child_by_type(node, "extends_clause")
        if extends_clause:
            for child in extends_clause.children:
                if child.type in ["identifier", "type_identifier"]:
                    base_classes.append(self._get_node_text(child))

        implements_clause = self._find_child_by_type(node, "implements_clause")  
        if implements_clause:
            for child in implements_clause.children:
                if child.type in ["identifier", "type_identifier"]:
                    base_classes.append(self._get_node_text(child))

        return base_classes

    def _extract_parameters(self, node) -> List[str]:
        parameters = []
        params_node = self._find_child_by_type(node, "formal_parameters")
        if params_node:
            for child in params_node.children:
                if child.type in ["identifier", "required_parameter", "optional_parameter"]:
                    if child.type == "identifier":
                        parameters.append(self._get_node_text(child))
                    else:
                        param_name = self._find_child_by_type(child, "identifier")
                        if param_name:
                            parameters.append(self._get_node_text(param_name))
        return parameters

    def _extract_all_relationships(self, node, all_entities: dict) -> None:
        self._traverse_for_relationships(node, all_entities, current_top_level=None)

    def _traverse_for_relationships(self, node, all_entities: dict, current_top_level: str = None) -> None:
        if current_top_level is None or self._is_new_top_level(node):
            new_top_level = self._get_top_level_name(node)
            if new_top_level and new_top_level in self.top_level_nodes:
                current_top_level = new_top_level


        if current_top_level:
            if node.type == "call_expression":
                self._extract_call_relationship(node, current_top_level, all_entities)
            elif node.type == "new_expression":
                self._extract_new_relationship(node, current_top_level, all_entities)

            elif node.type == "member_expression":
                self._extract_member_relationship(node, current_top_level, all_entities)
            elif node.type == "subscript_expression":
                self._extract_subscript_relationship(node, current_top_level, all_entities)

            elif node.type == "type_annotation":
                self._extract_type_relationship(node, current_top_level, all_entities)
            elif node.type == "type_arguments":
                self._extract_type_arguments_relationship(node, current_top_level, all_entities)

            elif node.type == "extends_clause":
                self._extract_inheritance_relationship(node, current_top_level, all_entities)
            elif node.type == "implements_clause":
                self._extract_inheritance_relationship(node, current_top_level, all_entities)

        for child in node.children:
            self._traverse_for_relationships(child, all_entities, current_top_level)

    def _is_new_top_level(self, node) -> bool:
        return node.type in [
            "function_declaration", "generator_function_declaration", 
            "class_declaration", "abstract_class_declaration",
            "interface_declaration", "type_alias_declaration", "enum_declaration",
            "export_statement"
        ]

    def _get_top_level_name(self, node) -> Optional[str]:
        result = None
        if node.type in ["function_declaration", "generator_function_declaration"]:
            name_node = self._find_child_by_type(node, "identifier")
            result = self._get_node_text(name_node) if name_node else None
        elif node.type in ["class_declaration", "abstract_class_declaration", "interface_declaration", "type_alias_declaration"]:
            name_node = self._find_child_by_type(node, "type_identifier") or self._find_child_by_type(node, "identifier")
            result = self._get_node_text(name_node) if name_node else None
        elif node.type == "enum_declaration":
            name_node = self._find_child_by_type(node, "identifier")
            result = self._get_node_text(name_node) if name_node else None
        elif node.type == "export_statement":
            if self._find_child_by_type(node, "default"):
                call_expr = self._find_child_by_type(node, "call_expression")
                if call_expr:
                    identifier = self._find_child_by_type(call_expr, "identifier")
                    if identifier:
                        return self._get_node_text(identifier)
                return "default_export"
            else:
                func_decl = self._find_child_by_type(node, "function_declaration")
                class_decl = self._find_child_by_type(node, "class_declaration")
                lexical_decl = self._find_child_by_type(node, "lexical_declaration")

                if func_decl:
                    name_node = self._find_child_by_type(func_decl, "identifier")
                    if name_node:
                        result = self._get_node_text(name_node)  
                elif class_decl:
                    name_node = self._find_child_by_type(class_decl, "type_identifier")
                    if name_node:
                        result = self._get_node_text(name_node)  
                elif lexical_decl:
                    var_declarator = self._find_child_by_type(lexical_decl, "variable_declarator")
                    if var_declarator:
                        name_node = self._find_child_by_type(var_declarator, "identifier")
                        if name_node:
                            result = self._get_node_text(name_node)  
                else:
                    result = "unnamed_export"
        elif node.type in ["lexical_declaration", "variable_declaration"]:
            # const/let/var declarations
            var_declarator = self._find_child_by_type(node, "variable_declarator")
            if var_declarator:
                name_node = self._find_child_by_type(var_declarator, "identifier")
                result = self._get_node_text(name_node) if name_node else None
            else:
                result = None
        else:
            result = None

        return result

    def _extract_call_relationship(self, node, caller_name: str, all_entities: dict) -> None:
        try:
            call_line = node.start_point[0] + 1
            callee_name = self._extract_callee_name(node)

            if not callee_name or self._is_builtin_function(callee_name):
                return

            call_text = self._get_node_text(node)
            is_method_call = "this." in call_text or "super." in call_text

            if is_method_call:
                current_class = None
                for entity_name, entity_data in all_entities.items():
                    if (entity_data.get('type') == 'class' and 
                        caller_name in entity_name): 
                        current_class = entity_name
                        break

                if current_class and callee_name in all_entities:
                    callee_entity = all_entities[callee_name]
                    if (callee_entity.get('subtype') == 'method' and 
                        callee_name in current_class):
                        return

            if callee_name in self.top_level_nodes:
                self._add_relationship(caller_name, callee_name, call_line)
            elif callee_name not in all_entities:
                self._add_relationship(caller_name, callee_name, call_line)
            elif callee_name in all_entities:
                entity_data = all_entities[callee_name]
                if self._is_actually_top_level(entity_data):
                    self._add_relationship(caller_name, callee_name, call_line)
                else:
                    logger.debug(f"Ignoring nested call: {caller_name} -> {callee_name} (local/nested)")
            else:
                logger.debug(f"Ignoring unknown call: {caller_name} -> {callee_name}")

        except Exception as e:
            logger.debug(f"Error extracting call relationship: {e}")

    def _extract_new_relationship(self, node, caller_name: str, all_entities: dict) -> None:
        try:
            call_line = node.start_point[0] + 1
            if node.children:
                constructor_node = None
                for child in node.children:
                    if child.type not in ['new', 'type_arguments', 'arguments']:
                        constructor_node = child
                        break

                if constructor_node:
                    constructor_name = self._get_node_text(constructor_node)

                    if constructor_name and not self._is_builtin_function(constructor_name):
                        self._add_relationship(caller_name, constructor_name, call_line)

        except Exception as e:
            logger.debug(f"Error extracting new relationship: {e}")

    def _extract_member_relationship(self, node, caller_name: str, all_entities: dict) -> None:
        try:
            call_line = node.start_point[0] + 1
            property_node = self._find_child_by_type(node, "property_identifier")
            if property_node:
                property_name = self._get_node_text(property_node)
                if property_name and not self._is_builtin_function(property_name):
                    self._add_relationship(caller_name, property_name, call_line)
        except Exception as e:
            logger.debug(f"Error extracting member relationship: {e}")

    def _extract_subscript_relationship(self, node, caller_name: str, all_entities: dict) -> None:
        pass

    def _extract_type_relationship(self, node, caller_name: str, all_entities: dict) -> None:
        try:
            type_identifiers = []
            self._find_all_type_identifiers(node, type_identifiers)

            call_line = node.start_point[0] + 1

            for type_node in type_identifiers:
                type_name = self._get_node_text(type_node)

                if self._is_builtin_type(type_name):
                    continue

                if type_name in all_entities:
                    target_name = self._resolve_to_top_level(type_name, all_entities)
                    if target_name and target_name in self.top_level_nodes:
                        self._add_relationship(caller_name, target_name, call_line)
                else:
                    self._add_relationship(caller_name, type_name, call_line)

        except Exception as e:
            logger.debug(f"Error extracting type relationship: {e}")

    def _find_all_type_identifiers(self, node, type_identifiers: list) -> None:
        if node.type == "type_identifier":
            type_identifiers.append(node)

        for child in node.children:
            self._find_all_type_identifiers(child, type_identifiers)

    def _extract_type_arguments_relationship(self, node, caller_name: str, all_entities: dict) -> None:
        try:
            for child in node.children:
                if child.type == "type_identifier":
                    type_name = self._get_node_text(child)
                    if type_name in all_entities:
                        target_name = self._resolve_to_top_level(type_name, all_entities)
                        if target_name and target_name in self.top_level_nodes:
                            call_line = node.start_point[0] + 1
                            self._add_relationship(caller_name, target_name, call_line)
        except Exception as e:
            logger.debug(f"Error extracting type arguments relationship: {e}")

    def _extract_inheritance_relationship(self, node, caller_name: str, all_entities: dict) -> None:
        """Extract inheritance/implementation relationships"""
        try:
            for child in node.children:
                if child.type in ["identifier", "type_identifier"]:
                    base_name = self._get_node_text(child)
                    if base_name in all_entities:
                        target_name = self._resolve_to_top_level(base_name, all_entities)
                        if target_name and target_name in self.top_level_nodes:
                            call_line = node.start_point[0] + 1
                            self._add_relationship(caller_name, target_name, call_line)
        except Exception as e:
            logger.debug(f"Error extracting inheritance relationship: {e}")

    def _resolve_to_top_level(self, entity_name: str, all_entities: dict) -> Optional[str]:
        if entity_name in self.top_level_nodes:
            return entity_name

        entity_data = all_entities.get(entity_name)
        if entity_data and entity_data.get('depth', 0) > 2:
            return None

        return entity_name if entity_name in self.top_level_nodes else None

    def _add_relationship(self, caller_name: str, callee_name: str, call_line: int) -> None:
        caller_id = f"{self._get_relative_path()}::{caller_name}"
        callee_id = f"{self._get_relative_path()}::{callee_name}"  

        relationship = CallRelationship(
            caller=caller_id,
            callee=callee_id,
            call_line=call_line,
            is_resolved=False,  
        )
        self.call_relationships.append(relationship)

    def _extract_callee_name(self, call_node) -> Optional[str]:
        if call_node.children:
            callee_node = call_node.children[0]

            if callee_node.type == "identifier":
                return self._get_node_text(callee_node)
            elif callee_node.type == "member_expression":
                return self._get_node_text(callee_node)
        return None

    def _is_builtin_type(self, name: str) -> bool:
        """Check if type name is a TypeScript/JavaScript built-in type."""
        builtin_types = {
            # Primitive types
            "string", "number", "boolean", "object", "undefined", "null", "void", "never", "any", "unknown"
        }
        return name in builtin_types

    def _is_builtin_function(self, name: str) -> bool:
        builtins = {}
        return name in builtins

    def _find_child_by_type(self, node, node_type: str):
        for child in node.children:
            if child.type == node_type:
                return child
        return None

    def _get_node_text(self, node) -> str:
        start_byte = node.start_byte
        end_byte = node.end_byte
        return self.content.encode("utf8")[start_byte:end_byte].decode("utf8")

def analyze_typescript_file_treesitter(
    file_path: str, content: str, repo_path: str = None
) -> Tuple[List[Node], List[CallRelationship]]:
    try:
        logger.debug(f"Tree-sitter TS analysis for {file_path}")
        analyzer = TreeSitterTSAnalyzer(file_path, content, repo_path)
        analyzer.analyze()
        logger.debug(
            f"Found {len(analyzer.nodes)} top-level nodes, {len(analyzer.call_relationships)} calls"
        )
        return analyzer.nodes, analyzer.call_relationships
    except Exception as e:
        logger.error(f"Error in tree-sitter TS analysis for {file_path}: {e}", exc_info=True)
        return [], []

